23	    public ResourceService(UsagePolicyRepository policyRepository,
24	                           ResourceItemRepository resourceRepository,
25	                           ClaimRecordRepository claimRecordRepository,
26	                           DownloadRecordRepository downloadRecordRepository,
27	                           PrintableNoticeRepository noticeRepository,
28	                           ShippingAddressRepository addressRepository,
29	                           AuditService auditService) {
30	        this.policyRepository = policyRepository;
31	        this.resourceRepository = resourceRepository;
32	        this.claimRecordRepository = claimRecordRepository;
