39	    @Transactional
40	    public UsagePolicy createPolicy(String name, String scope, int maxActions, int windowDays,
41	                                     String resourceAction, Long actorId, String actorRole) {
42	        UsagePolicy policy = new UsagePolicy();
43	        policy.setName(name);
44	        policy.setScope(scope);
45	        policy.setMaxActions(maxActions);
46	        policy.setWindowDays(windowDays);
47	        policy.setResourceAction(resourceAction);
48	        policy.setCreatedAt(LocalDateTime.now());
49	
50	        UsagePolicy saved = policyRepository.save(policy);
51	
52	        auditService.log(actorId, actorRole, "POLICY_CREATED",
53	                "UsagePolicy", saved.getId().toString(),
54	                null, null, null, null);
55	
56	        return saved;
57	    }
