59	    @Transactional
60	    public ResourceItem publishResource(String type, String title, String description,
61	                                         Integer inventoryCount, String fileVersion,
62	                                         String filePath, Long fileSize, String contentType,
63	                                         Long usagePolicyId, String status,
64	                                         Long actorId, String actorRole) {
65	        ResourceItem item = new ResourceItem();
66	        item.setType(type);
67	        item.setTitle(title);
68	        item.setDescription(description);
69	        item.setInventoryCount(inventoryCount);
70	        item.setFileVersion(fileVersion);
71	        item.setFilePath(filePath);
72	        item.setFileSize(fileSize);
73	        item.setContentType(contentType);
74	        item.setUsagePolicyId(usagePolicyId);
75	        item.setStatus(status != null ? status : "PUBLISHED");
