102	    /**
103	     * Claims a resource for the given account. Household-scoped limits are enforced
104	     * using the participant's approved primary shipping address as the offline household key.
105	     */
106	    @Transactional
107	    public ClaimResult claimResource(Long resourceId, Long accountId) {
108	        ResourceItem resource = resourceRepository.findById(resourceId)
109	                .orElseThrow(() -> new IllegalArgumentException("Resource not found: " + resourceId));
110	
111	        // Derive household key from primary address
112	        String householdKey = deriveHouseholdKey(accountId);
113	
114	        // Evaluate policy
115	        if (resource.getUsagePolicyId() != null) {
116	            UsagePolicy policy = policyRepository.findById(resource.getUsagePolicyId())
117	                    .orElse(null);
118	            if (policy != null && "CLAIM".equals(policy.getResourceAction())) {
119	                LocalDateTime windowStart = LocalDateTime.now().minusDays(policy.getWindowDays());
120	                long count;
121	                if ("HOUSEHOLD".equals(policy.getScope())) {
122	                    if (householdKey == null) {
123	                        throw new IllegalStateException(
124	                                "Household-scoped policy requires a primary shipping address. Please add an address first.");
125	                    }
126	                    count = claimRecordRepository.countByResourceIdAndHouseholdKeyAndResultAndCreatedAtAfter(
127	                            resourceId, householdKey, "ALLOWED", windowStart);
128	                } else {
129	                    count = claimRecordRepository.countByResourceIdAndAccountIdAndResultAndCreatedAtAfter(
130	                            resourceId, accountId, "ALLOWED", windowStart);
131	                }
132	                if (count >= policy.getMaxActions()) {
133	                    ClaimRecord denied = createClaimRecord(resourceId, accountId, householdKey,
134	                            "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED");
135	                    auditService.log(accountId, null, "RESOURCE_CLAIM_DENIED",
136	                            "ClaimRecord", denied.getId().toString(),
137	                            null, "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED", null);
138	                    return new ClaimResult(denied, null);
139	                }
140	            }
141	        }
142	
143	        // Check inventory
144	        if (resource.getInventoryCount() != null && resource.getInventoryCount() <= 0) {
145	            ClaimRecord denied = createClaimRecord(resourceId, accountId, householdKey,
146	                    "DENIED_POLICY", "OUT_OF_STOCK");
147	            auditService.log(accountId, null, "RESOURCE_CLAIM_DENIED",
148	                    "ClaimRecord", denied.getId().toString(),
149	                    null, "DENIED_POLICY", "OUT_OF_STOCK", null);
150	            return new ClaimResult(denied, null);
151	        }
152	
153	        // Decrement inventory
154	        if (resource.getInventoryCount() != null) {
155	            resource.setInventoryCount(resource.getInventoryCount() - 1);
156	            resource.setUpdatedAt(LocalDateTime.now());
157	            resourceRepository.save(resource);
158	        }
159	
160	        ClaimRecord claim = createClaimRecord(resourceId, accountId, householdKey, "ALLOWED", null);
161	
162	        // Create printable notice
163	        PrintableNotice notice = new PrintableNotice();
164	        notice.setAccountId(accountId);
165	        notice.setResourceId(resourceId);
166	        notice.setNoticeType("CLAIM_CONFIRMATION");
167	        notice.setContent("Resource claimed: " + resource.getTitle() + " (Claim ID: " + claim.getId() + ")");
168	        notice.setCreatedAt(LocalDateTime.now());
169	        PrintableNotice savedNotice = noticeRepository.save(notice);
170	
171	        auditService.log(accountId, null, "RESOURCE_CLAIMED",
172	                "ClaimRecord", claim.getId().toString(),
173	                null, "ALLOWED", null, null);
174	
175	        return new ClaimResult(claim, savedNotice);
176	    }
177	
178	    @Transactional
179	    public DownloadResult downloadResource(Long resourceId, Long accountId, String fileVersion) {
180	        ResourceItem resource = resourceRepository.findById(resourceId)
181	                .orElseThrow(() -> new IllegalArgumentException("Resource not found: " + resourceId));
182	
183	        // Evaluate policy
184	        if (resource.getUsagePolicyId() != null) {
185	            UsagePolicy policy = policyRepository.findById(resource.getUsagePolicyId())
186	                    .orElse(null);
187	            if (policy != null && "DOWNLOAD".equals(policy.getResourceAction())) {
188	                LocalDateTime windowStart = LocalDateTime.now().minusDays(policy.getWindowDays());
189	                long count = downloadRecordRepository.countByResourceIdAndAccountIdAndResultAndCreatedAtAfter(
190	                        resourceId, accountId, "ALLOWED", windowStart);
191	                if (count >= policy.getMaxActions()) {
192	                    DownloadRecord denied = createDownloadRecord(resourceId, accountId, fileVersion,
193	                            "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED");
194	                    auditService.log(accountId, null, "RESOURCE_DOWNLOAD_DENIED",
195	                            "DownloadRecord", denied.getId().toString(),
196	                            null, "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED", null);
197	                    return new DownloadResult(denied);
198	                }
199	            }
200	        }
201	
202	        DownloadRecord record = createDownloadRecord(resourceId, accountId, fileVersion, "ALLOWED", null);
203	
204	        auditService.log(accountId, null, "RESOURCE_DOWNLOADED",
205	                "DownloadRecord", record.getId().toString(),
206	                null, "ALLOWED", null, null);
207	
208	        return new DownloadResult(record);
209	    }
210	
211	    public byte[] getResourceFileContent(Long resourceId, Long accountId) {
212	        List<DownloadRecord> records = downloadRecordRepository.findByResourceIdAndAccountId(resourceId, accountId);
213	        boolean hasAllowed = records.stream().anyMatch(r -> "ALLOWED".equals(r.getResult()));
214	        if (!hasAllowed) {
215	            return null;
216	        }
217	        ResourceItem resource = resourceRepository.findById(resourceId)
218	                .orElseThrow(() -> new IllegalArgumentException("Resource not found"));
219	
220	        // Read actual file bytes from local disk storage
221	        if (resource.getFilePath() != null) {
222	            try {
223	                java.nio.file.Path path = java.nio.file.Paths.get(resource.getFilePath());
224	                return java.nio.file.Files.readAllBytes(path);
225	            } catch (java.io.IOException e) {
226	                throw new IllegalStateException("Failed to read resource file: " + e.getMessage(), e);
227	            }
228	        }
229	
230	        // Fallback for legacy resources without file_path (should not happen for new resources)
231	        return null;
232	    }
233	
234	    public PrintableNotice getNotice(Long noticeId) {
235	        return noticeRepository.findById(noticeId)
236	                .orElseThrow(() -> new IllegalArgumentException("Notice not found: " + noticeId));
237	    }
238	
239	    private ClaimRecord createClaimRecord(Long resourceId, Long accountId, String householdKey,
240	                                           String result, String reasonCode) {
241	        ClaimRecord record = new ClaimRecord();
242	        record.setResourceId(resourceId);
243	        record.setAccountId(accountId);
244	        record.setHouseholdKey(householdKey);
245	        record.setResult(result);
246	        record.setReasonCode(reasonCode);
247	        record.setCreatedAt(LocalDateTime.now());
248	        return claimRecordRepository.save(record);
249	    }
250	
251	    private DownloadRecord createDownloadRecord(Long resourceId, Long accountId, String fileVersion,
252	                                                 String result, String reasonCode) {
253	        DownloadRecord record = new DownloadRecord();
254	        record.setResourceId(resourceId);
255	        record.setAccountId(accountId);
256	        record.setFileVersion(fileVersion);
257	        record.setResult(result);
258	        record.setReasonCode(reasonCode);
259	        record.setCreatedAt(LocalDateTime.now());
260	        return downloadRecordRepository.save(record);
261	    }
262	
263	    /**
264	     * Derives the household key from the participant's primary shipping address.
265	     * Uses normalized city + state + zip as the offline household identifier.
266	     * Returns null if no primary address exists.
267	     */
268	    private String deriveHouseholdKey(Long accountId) {
269	        List<ShippingAddress> addresses = addressRepository.findByAccountId(accountId);
270	        ShippingAddress primary = addresses.stream()
271	                .filter(ShippingAddress::isPrimary)
272	                .findFirst()
273	                .orElse(null);
274	        if (primary == null) {
275	            return null;
276	        }
277	        // Normalize: city (lowercase) + state + zip
278	        return (primary.getCity().toLowerCase().trim() + "|" +
279	                primary.getStateCode().toUpperCase().trim() + "|" +
280	                primary.getZipCode().trim());
281	    }
282	
283	    public record ClaimResult(ClaimRecord claimRecord, PrintableNotice notice) {}
284	    public record DownloadResult(DownloadRecord downloadRecord) {}
285	}
