1	package com.croh.resources;
2	
3	import com.croh.resources.dto.ClaimRequest;
4	import com.croh.resources.dto.ClaimResponse;
5	import com.croh.resources.dto.DownloadRequest;
6	import com.croh.resources.dto.DownloadResponse;
7	import com.croh.resources.dto.ResourceRequest;
8	import com.croh.resources.dto.ResourceResponse;
9	import com.croh.security.Permission;
10	import com.croh.security.RequirePermission;
11	import com.croh.security.SessionAccount;
12	import jakarta.validation.Valid;
13	import org.springframework.http.ResponseEntity;
14	import org.springframework.security.core.Authentication;
15	import org.springframework.security.core.context.SecurityContextHolder;
16	import org.springframework.web.bind.annotation.GetMapping;
17	import org.springframework.web.bind.annotation.PathVariable;
18	import org.springframework.web.bind.annotation.PostMapping;
19	import org.springframework.web.bind.annotation.RequestBody;
20	import org.springframework.web.bind.annotation.RequestMapping;
21	import org.springframework.web.bind.annotation.RestController;
22	
23	import java.util.List;
24	
25	@RestController
26	@RequestMapping("/api/v1/resources")
27	public class ResourceController {
28	
29	    private final ResourceService resourceService;
30	
31	    public ResourceController(ResourceService resourceService) {
32	        this.resourceService = resourceService;
33	    }
34	
35	    @PostMapping
36	    @RequirePermission(Permission.PUBLISH_RESOURCE)
37	    public ResponseEntity<ResourceResponse> publishResource(@Valid @RequestBody ResourceRequest request) {
38	        SessionAccount actor = getSessionAccount();
39	        ResourceItem item = resourceService.publishResource(
40	                request.type(), request.title(), request.description(),
41	                request.inventoryCount(), request.fileVersion(),
42	                request.filePath(), request.fileSize(), request.contentType(),
43	                request.usagePolicyId(),
44	                request.status(), actor.accountId(), actor.activeRole().name());
45	        return ResponseEntity.status(201).body(toResponse(item));
46	    }
47	
48	    @GetMapping
49	    public ResponseEntity<List<ResourceResponse>> listResources() {
50	        List<ResourceResponse> resources = resourceService.listResources().stream()
51	                .map(this::toResponse)
52	                .toList();
53	        return ResponseEntity.ok(resources);
54	    }
55	
56	    @GetMapping("/{id}")
57	    public ResponseEntity<ResourceResponse> getResource(@PathVariable Long id) {
58	        ResourceItem item = resourceService.getResource(id);
59	        return ResponseEntity.ok(toResponse(item));
60	    }
61	
62	    @PostMapping("/{id}/claim")
63	    public ResponseEntity<ClaimResponse> claimResource(@PathVariable Long id) {
64	        SessionAccount actor = getSessionAccount();
65	        ResourceService.ClaimResult result = resourceService.claimResource(
66	                id, actor.accountId());
67	        ClaimRecord claim = result.claimRecord();
68	        Long noticeId = result.notice() != null ? result.notice().getId() : null;
69	        return ResponseEntity.ok(new ClaimResponse(claim.getId(), claim.getResult(),
70	                claim.getReasonCode(), noticeId));
71	    }
72	
73	    @PostMapping("/files/{id}/download")
74	    public ResponseEntity<DownloadResponse> downloadResource(@PathVariable Long id,
75	                                                              @RequestBody DownloadRequest request) {
76	        SessionAccount actor = getSessionAccount();
77	        ResourceService.DownloadResult result = resourceService.downloadResource(
78	                id, actor.accountId(), request.fileVersion());
79	        DownloadRecord record = result.downloadRecord();
80	        return ResponseEntity.ok(new DownloadResponse(record.getId(), record.getResult(),
81	                record.getReasonCode()));
82	    }
83	
84	    @GetMapping("/{id}/file")
85	    public ResponseEntity<byte[]> getResourceFile(@PathVariable Long id) {
86	        SessionAccount actor = getSessionAccount();
87	        ResourceItem resource = resourceService.getResource(id);
88	        if (!"DOWNLOADABLE_FILE".equals(resource.getType())) {
89	            return ResponseEntity.badRequest().build();
90	        }
91	        // Verify the user has a successful download record for this resource
92	        byte[] fileData = resourceService.getResourceFileContent(id, actor.accountId());
93	        if (fileData == null) {
94	            return ResponseEntity.status(403).build();
95	        }
96	        String ct = resource.getContentType() != null ? resource.getContentType() : "application/octet-stream";
97	        String filename = resource.getFilePath() != null
98	                ? java.nio.file.Paths.get(resource.getFilePath()).getFileName().toString()
99	                : "resource-" + id;
100	        return ResponseEntity.ok()
101	                .header("Content-Type", ct)
102	                .header("Content-Disposition", "attachment; filename=\"" + filename + "\"")
103	                .body(fileData);
104	    }
105	
106	    private ResourceResponse toResponse(ResourceItem r) {
107	        return new ResourceResponse(r.getId(), r.getType(), r.getTitle(), r.getDescription(),
108	                r.getInventoryCount(), r.getFileVersion(), r.getFileSize(), r.getContentType(),
109	                r.getUsagePolicyId(),
110	                r.getStatus(), r.getCreatedBy(), r.getCreatedAt(), r.getUpdatedAt());
111	    }
112	
113	    private SessionAccount getSessionAccount() {
114	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
115	        return (SessionAccount) auth.getPrincipal();
116	    }
117	}
