1	package com.croh.events;
2	
3	import com.croh.audit.AuditService;
4	import com.croh.reporting.ExportService;
5	import org.springframework.stereotype.Service;
6	import org.springframework.transaction.annotation.Transactional;
7	
8	import java.time.LocalDateTime;
9	import java.util.ArrayList;
10	import java.util.List;
11	import java.util.stream.Collectors;
12	
13	@Service
14	public class EventService {
15	
16	    private final EventRepository eventRepository;
17	    private final EventRegistrationRepository registrationRepository;
18	    private final AuditService auditService;
19	    private final ExportService exportService;
20	
21	    public EventService(EventRepository eventRepository,
22	                        EventRegistrationRepository registrationRepository,
23	                        AuditService auditService,
24	                        ExportService exportService) {
25	        this.eventRepository = eventRepository;
26	        this.registrationRepository = registrationRepository;
27	        this.auditService = auditService;
28	        this.exportService = exportService;
29	    }
30	
31	    @Transactional
32	    public Event createEvent(String organizationId, String title, String description,
33	                             String mode, String location, LocalDateTime startAt, LocalDateTime endAt,
34	                             Integer capacity, Boolean waitlistEnabled, Boolean manualReviewRequired,
35	                             String registrationFormSchema, String status, Long actorId, String actorRole) {
36	        Event event = new Event();
37	        event.setOrganizationId(organizationId);
38	        event.setTitle(title);
39	        event.setDescription(description);
40	        event.setMode(mode != null ? mode : "ON_SITE");
41	        event.setLocation(location);
42	        event.setStartAt(startAt);
43	        event.setEndAt(endAt);
44	        event.setCapacity(capacity != null ? capacity : 50);
45	        event.setWaitlistEnabled(waitlistEnabled != null ? waitlistEnabled : false);
46	        event.setManualReviewRequired(manualReviewRequired != null ? manualReviewRequired : false);
47	        event.setRegistrationFormSchema(registrationFormSchema);
48	        event.setStatus(status != null ? status : "DRAFT");
49	        event.setCreatedBy(actorId);
50	        event.setCreatedAt(LocalDateTime.now());
51	        event.setUpdatedAt(LocalDateTime.now());
52	
53	        Event saved = eventRepository.save(event);
54	
55	        auditService.log(actorId, actorRole, "EVENT_CREATED",
56	                "Event", saved.getId().toString(),
57	                null, saved.getStatus(), null, null);
58	
59	        return saved;
60	    }
61	
62	    public List<Event> listEvents() {
63	        return eventRepository.findByStatus("PUBLISHED");
64	    }
65	
66	    public Event getEvent(Long id) {
67	        return eventRepository.findById(id)
68	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + id));
69	    }
70	
71	    @Transactional
72	    public Event updateEvent(Long id, String title, String description, String mode,
73	                             String location, LocalDateTime startAt, LocalDateTime endAt,
74	                             Integer capacity, Boolean waitlistEnabled, Boolean manualReviewRequired,
75	                             String registrationFormSchema, String status,
76	                             Long actorId, String actorRole) {
77	        Event event = eventRepository.findById(id)
78	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + id));
79	
80	        // Object-level authorization: only the event creator can update it
81	        if (!event.getCreatedBy().equals(actorId)) {
82	            throw new SecurityException("Cannot update an event you did not create");
83	        }
84	
85	        String beforeStatus = event.getStatus();
86	
87	        if (title != null) event.setTitle(title);
88	        if (description != null) event.setDescription(description);
89	        if (mode != null) event.setMode(mode);
90	        if (location != null) event.setLocation(location);
91	        if (startAt != null) event.setStartAt(startAt);
92	        if (endAt != null) event.setEndAt(endAt);
93	        if (capacity != null) event.setCapacity(capacity);
94	        if (waitlistEnabled != null) event.setWaitlistEnabled(waitlistEnabled);
95	        if (manualReviewRequired != null) event.setManualReviewRequired(manualReviewRequired);
96	        if (registrationFormSchema != null) event.setRegistrationFormSchema(registrationFormSchema);
97	        if (status != null) event.setStatus(status);
98	        event.setUpdatedAt(LocalDateTime.now());
99	
100	        Event saved = eventRepository.save(event);
101	
102	        auditService.log(actorId, actorRole, "EVENT_UPDATED",
103	                "Event", saved.getId().toString(),
104	                beforeStatus, saved.getStatus(), null, null);
105	
106	        return saved;
107	    }
108	
109	    @Transactional
110	    public EventRegistration register(Long eventId, Long accountId, String formResponses) {
111	        Event event = eventRepository.findById(eventId)
112	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + eventId));
113	
114	        long approvedCount = registrationRepository.countByEventIdAndStatus(eventId, "APPROVED");
115	
116	        String regStatus;
117	        if (event.isManualReviewRequired()) {
118	            regStatus = "PENDING_REVIEW";
119	        } else if (approvedCount < event.getCapacity()) {
120	            regStatus = "APPROVED";
121	        } else if (event.isWaitlistEnabled()) {
122	            regStatus = "WAITLISTED";
123	        } else {
124	            throw new IllegalStateException("Event is full and waitlist is not enabled");
125	        }
126	
127	        EventRegistration reg = new EventRegistration();
128	        reg.setEventId(eventId);
129	        reg.setAccountId(accountId);
130	        reg.setStatus(regStatus);
131	        reg.setFormResponses(formResponses);
132	        reg.setCreatedAt(LocalDateTime.now());
133	        reg.setUpdatedAt(LocalDateTime.now());
134	
135	        EventRegistration saved = registrationRepository.save(reg);
136	
137	        auditService.log(accountId, null, "REGISTRATION_SUBMITTED",
138	                "EventRegistration", saved.getId().toString(),
139	                null, regStatus, null, null);
140	
141	        return saved;
142	    }
143	
144	    @Transactional
145	    public EventRegistration decideRegistration(Long regId, String decision, String note,
146	                                                 Long actorId, String actorRole) {
147	        if (!"APPROVE".equals(decision) && !"DENY".equals(decision)) {
148	            throw new IllegalArgumentException("Decision must be APPROVE or DENY");
149	        }
150	
151	        EventRegistration reg = registrationRepository.findById(regId)
152	                .orElseThrow(() -> new IllegalArgumentException("Registration not found: " + regId));
153	
154	        String beforeStatus = reg.getStatus();
155	
156	        if ("APPROVE".equals(decision)) {
157	            Event event = eventRepository.findById(reg.getEventId())
158	                    .orElseThrow(() -> new IllegalArgumentException("Event not found: " + reg.getEventId()));
159	            long approvedCount = registrationRepository.countByEventIdAndStatus(reg.getEventId(), "APPROVED");
160	            if (approvedCount >= event.getCapacity()) {
161	                throw new IllegalStateException("Event is at capacity, cannot approve registration");
162	            }
163	            reg.setStatus("APPROVED");
164	        } else {
165	            reg.setStatus("DENIED");
166	        }
167	
168	        reg.setReviewNote(note);
169	        reg.setReviewedBy(actorId);
170	        reg.setUpdatedAt(LocalDateTime.now());
171	
172	        EventRegistration saved = registrationRepository.save(reg);
173	
174	        auditService.log(actorId, actorRole, "REGISTRATION_DECIDED",
175	                "EventRegistration", saved.getId().toString(),
176	                beforeStatus, saved.getStatus(), decision, null);
177	
178	        return saved;
179	    }
180	
181	    @Transactional
182	    public EventRegistration cancelRegistration(Long regId, Long actorId) {
183	        EventRegistration reg = registrationRepository.findById(regId)
184	                .orElseThrow(() -> new IllegalArgumentException("Registration not found: " + regId));
185	
186	        if (!reg.getAccountId().equals(actorId)) {
187	            throw new SecurityException("Cannot cancel another user's registration");
188	        }
189	
190	        String beforeStatus = reg.getStatus();
191	        boolean wasApproved = "APPROVED".equals(beforeStatus);
192	
193	        reg.setStatus("CANCELLED");
194	        reg.setUpdatedAt(LocalDateTime.now());
195	        registrationRepository.save(reg);
196	
197	        auditService.log(actorId, null, "REGISTRATION_CANCELLED",
198	                "EventRegistration", reg.getId().toString(),
199	                beforeStatus, "CANCELLED", null, null);
200	
201	        // Auto-promote oldest waitlisted entry if the cancelled reg was approved
202	        if (wasApproved) {
203	            List<EventRegistration> waitlisted = registrationRepository
204	                    .findByEventIdAndStatus(reg.getEventId(), "WAITLISTED");
205	            if (!waitlisted.isEmpty()) {
206	                // Find oldest by createdAt
207	                EventRegistration oldest = waitlisted.stream()
208	                        .min((a, b) -> a.getCreatedAt().compareTo(b.getCreatedAt()))
209	                        .get();
210	                oldest.setStatus("APPROVED");
211	                oldest.setUpdatedAt(LocalDateTime.now());
212	                registrationRepository.save(oldest);
213	
214	                auditService.log(actorId, null, "REGISTRATION_AUTO_PROMOTED",
215	                        "EventRegistration", oldest.getId().toString(),
216	                        "WAITLISTED", "APPROVED", "WAITLIST_PROMOTION", null);
217	            }
218	        }
219	
220	        return reg;
221	    }
