235	    public String exportRoster(Long eventId, String format, Long actorId, String actorRole) {
236	        List<EventRegistration> approved = registrationRepository.findByEventIdAndStatus(eventId, "APPROVED");
237	        Event event = eventRepository.findById(eventId)
238	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + eventId));
239	
240	        List<String> headers = List.of("Registration ID", "Event ID", "Account ID", "Status", "Registered At");
241	        List<List<String>> rows = new ArrayList<>();
242	        StringBuilder csv = new StringBuilder();
243	        csv.append(String.join(",", headers)).append("\n");
244	
245	        for (EventRegistration reg : approved) {
246	            List<String> row = List.of(
247	                    reg.getId().toString(),
248	                    reg.getEventId().toString(),
249	                    reg.getAccountId().toString(),
250	                    reg.getStatus(),
251	                    reg.getCreatedAt().toString());
252	            rows.add(row);
253	            csv.append(String.join(",", row)).append("\n");
254	        }
255	
256	        String exportPath;
257	        if ("PDF".equalsIgnoreCase(format)) {
258	            exportPath = exportService.exportPdf("Roster: " + event.getTitle(), headers, rows, "roster-" + eventId);
259	        } else {
260	            exportPath = exportService.exportCsv(csv.toString(), "roster-" + eventId);
261	        }
262	
263	        auditService.log(actorId, actorRole, "ROSTER_EXPORTED",
264	                "Event", eventId.toString(),
265	                null, exportPath, format, null);
266	
267	        return exportPath;
268	    }
