22	    @ExceptionHandler(MethodArgumentNotValidException.class)
23	    public ResponseEntity<ErrorResponse> handleValidation(MethodArgumentNotValidException ex) {
24	        List<ErrorResponse.FieldError> fieldErrors = ex.getBindingResult().getFieldErrors().stream()
25	                .map(fe -> new ErrorResponse.FieldError(
