29	                ))
30	                .toList();
31	
32	        ErrorResponse response = new ErrorResponse(
33	                "VALIDATION_ERROR",
34	                "Request validation failed",
35	                fieldErrors,
36	                UUID.randomUUID().toString(),
37	                Instant.now()
38	        );
39	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(response);
40	    }
