89	
90	    @ExceptionHandler(IllegalArgumentException.class)
91	    public ResponseEntity<ErrorResponse> handleIllegalArgument(IllegalArgumentException ex) {
92	        ErrorResponse response = new ErrorResponse(
93	                "VALIDATION_ERROR",
94	                ex.getMessage(),
95	                List.of(),
96	                UUID.randomUUID().toString(),
97	                Instant.now()
98	        );
99	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(response);
100	    }
101	
102	    @ExceptionHandler(DuplicateException.class)
103	    public ResponseEntity<ErrorResponse> handleDuplicate(DuplicateException ex) {
104	        ErrorResponse response = new ErrorResponse(
105	                "CONFLICT",
106	                ex.getMessage(),
107	                List.of(),
108	                UUID.randomUUID().toString(),
109	                Instant.now()
110	        );
111	        return ResponseEntity.status(HttpStatus.CONFLICT).body(response);
112	    }
113	
114	    @ExceptionHandler(IllegalStateException.class)
115	    public ResponseEntity<ErrorResponse> handleIllegalState(IllegalStateException ex) {
116	        ErrorResponse response = new ErrorResponse(
117	                "CONFLICT",
118	                ex.getMessage(),
119	                List.of(),
120	                UUID.randomUUID().toString(),
121	                Instant.now()
122	        );
123	        return ResponseEntity.status(HttpStatus.CONFLICT).body(response);
124	    }
125	
126	    @ExceptionHandler(Exception.class)
127	    public ResponseEntity<ErrorResponse> handleGeneric(Exception ex) {
128	        String correlationId = UUID.randomUUID().toString();
129	        log.error("Unhandled exception [correlationId={}]", correlationId, ex);
130	        ErrorResponse response = new ErrorResponse(
131	                "INTERNAL_ERROR",
132	                "An unexpected error occurred",
133	                List.of(),
134	                correlationId,
135	                Instant.now()
136	        );
137	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
