98	    @Transactional
99	    public ShippingAddress createAddress(Long accountId, String line1, String line2,
100	                                          String city, String state, String zip) {
101	        if (!STATE_PATTERN.matcher(state).matches()) {
102	            throw new IllegalArgumentException("State must be a 2-character uppercase code");
103	        }
104	        if (!ZIP_PATTERN.matcher(zip).matches()) {
105	            throw new IllegalArgumentException("Zip code must be in 5-digit or 5+4 format");
106	        }
107	
108	        // Auto-primary: first address for an account becomes primary
109	        List<ShippingAddress> existing = addressRepository.findByAccountId(accountId);
110	        boolean shouldBePrimary = existing.isEmpty();
111	
112	        ShippingAddress addr = new ShippingAddress();
113	        addr.setAccountId(accountId);
114	        addr.setAddressLine1Encrypted(encryptionService.encrypt(line1));
115	        addr.setAddressLine2Encrypted(line2 != null ? encryptionService.encrypt(line2) : null);
116	        addr.setCity(city);
117	        addr.setStateCode(state);
118	        addr.setZipCode(zip);
119	        addr.setPrimary(shouldBePrimary);
120	        addr.setCreatedAt(LocalDateTime.now());
121	
122	        ShippingAddress saved = addressRepository.save(addr);
123	
124	        auditService.log(accountId, null, "ADDRESS_CREATED",
125	                "ShippingAddress", saved.getId().toString(),
126	                null, shouldBePrimary ? "PRIMARY" : null, null, null);
