131	    @Transactional
132	    public ShippingAddress setPrimaryAddress(Long accountId, Long addressId) {
133	        ShippingAddress target = addressRepository.findById(addressId)
134	                .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
135	        if (!target.getAccountId().equals(accountId)) {
136	            throw new SecurityException("Cannot modify another user's address");
137	        }
138	
139	        // Clear existing primary
140	        List<ShippingAddress> all = addressRepository.findByAccountId(accountId);
141	        for (ShippingAddress a : all) {
142	            if (a.isPrimary()) {
143	                a.setPrimary(false);
144	                addressRepository.save(a);
145	            }
146	        }
147	
148	        target.setPrimary(true);
149	        ShippingAddress saved = addressRepository.save(target);
150	
151	        auditService.log(accountId, null, "ADDRESS_SET_PRIMARY",
152	                "ShippingAddress", saved.getId().toString(),
153	                null, "PRIMARY", null, null);
154	
155	        return saved;
