162	    @Transactional
163	    public RewardOrder placeOrder(Long rewardId, Long accountId, Integer quantity,
164	                                   String fulfillmentType, Long addressId) {
165	        // Validate address ownership if shipping
166	        if (addressId != null) {
167	            ShippingAddress addr = addressRepository.findById(addressId)
168	                    .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
169	            if (!addr.getAccountId().equals(accountId)) {
170	                throw new SecurityException("Cannot use another user's shipping address");
171	            }
172	        }
173	
174	        RewardItem reward = rewardRepository.findById(rewardId)
175	                .orElseThrow(() -> new IllegalArgumentException("Reward not found: " + rewardId));
176	
177	        int qty = quantity != null ? quantity : 1;
178	
179	        // Check per-user limit
180	        long existingOrders = orderRepository.countByRewardIdAndAccountId(rewardId, accountId);
181	        if (existingOrders + qty > reward.getPerUserLimit()) {
182	            throw new IllegalStateException("Per-user limit exceeded for this reward");
183	        }
184	
185	        // Check inventory
186	        if (reward.getInventoryCount() < qty) {
187	            throw new IllegalStateException("Insufficient inventory for this reward");
188	        }
189	
190	        // Decrement inventory
191	        reward.setInventoryCount(reward.getInventoryCount() - qty);
192	        reward.setUpdatedAt(LocalDateTime.now());
193	        rewardRepository.save(reward);
194	
195	        RewardOrder order = new RewardOrder();
196	        order.setRewardId(rewardId);
197	        order.setAccountId(accountId);
198	        order.setQuantity(qty);
199	        order.setFulfillmentType(fulfillmentType != null ? fulfillmentType : reward.getFulfillmentType());
200	        order.setShippingAddressId(addressId);
201	        order.setStatus("ORDERED");
202	        order.setCreatedAt(LocalDateTime.now());
203	        order.setUpdatedAt(LocalDateTime.now());
204	
205	        RewardOrder saved = orderRepository.save(order);
206	
207	        auditService.log(accountId, null, "ORDER_PLACED",
208	                "RewardOrder", saved.getId().toString(),
209	                null, "ORDERED", null, null);
210	
211	        return saved;
212	    }
