214	    @Transactional
215	    public RewardOrder transitionOrder(Long orderId, String toState, String note,
216	                                        Long actorId, String actorRole) {
217	        RewardOrder order = orderRepository.findById(orderId)
218	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
219	
220	        String beforeState = order.getStatus();
221	        Map<String, Set<String>> transitions = "VOUCHER".equals(order.getFulfillmentType())
222	                ? VOUCHER_TRANSITIONS : PHYSICAL_TRANSITIONS;
223	
224	        Set<String> allowedNext = transitions.get(beforeState);
225	        if (allowedNext == null || !allowedNext.contains(toState)) {
226	            throw new IllegalStateException(
227	                    "Invalid transition from " + beforeState + " to " + toState);
228	        }
229	
230	        order.setStatus(toState);
231	        if (note != null) order.setNote(note);
232	        order.setUpdatedAt(LocalDateTime.now());
233	
234	        RewardOrder saved = orderRepository.save(order);
235	
236	        auditService.log(actorId, actorRole, "ORDER_TRANSITIONED",
237	                "RewardOrder", saved.getId().toString(),
238	                beforeState, toState, null, null);
239	
240	        return saved;
241	    }
