288	    @Transactional
289	    public FulfillmentException transitionException(Long exceptionId, String toState,
290	                                                     Long actorId, String actorRole) {
291	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
292	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
293	
294	        String beforeState = exc.getStatus();
295	        Set<String> allowedNext = EXCEPTION_TRANSITIONS.get(beforeState);
296	        if (allowedNext == null || !allowedNext.contains(toState)) {
297	            throw new IllegalStateException(
298	                    "Invalid transition from " + beforeState + " to " + toState);
299	        }
300	
301	        exc.setStatus(toState);
302	        if ("RESOLVED".equals(toState) || "REJECTED".equals(toState)) {
303	            exc.setResolvedBy(actorId);
304	        }
305	        exc.setUpdatedAt(LocalDateTime.now());
306	
307	        FulfillmentException saved = exceptionRepository.save(exc);
308	
309	        auditService.log(actorId, actorRole, "EXCEPTION_TRANSITIONED",
310	                "FulfillmentException", saved.getId().toString(),
311	                beforeState, toState, null, null);
312	
313	        return saved;
314	    }
315	
316	    @Transactional
317	    public FulfillmentException reopenException(Long exceptionId, String reasonCode, String note,
318	                                                 Long actorId, String actorRole) {
319	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
320	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
321	
322	        if (!"RESOLVED".equals(exc.getStatus()) && !"REJECTED".equals(exc.getStatus())) {
323	            throw new IllegalStateException("Can only reopen from RESOLVED or REJECTED state");
324	        }
325	
326	        String beforeState = exc.getStatus();
327	        exc.setStatus("OPEN");
328	        exc.setReopenReason(note);
329	        exc.setSupervisorApproval(true);
330	        exc.setResolvedBy(null);
331	        exc.setUpdatedAt(LocalDateTime.now());
332	
333	        FulfillmentException saved = exceptionRepository.save(exc);
334	
335	        auditService.log(actorId, actorRole, "EXCEPTION_REOPENED",
336	                "FulfillmentException", saved.getId().toString(),
337	                beforeState, "OPEN", reasonCode, null);
338	
339	        return saved;
340	    }
