10	
11	@Service
12	public class AnalyticsService {
13	
14	    private final EntityManager entityManager;
15	
16	    public AnalyticsService(EntityManager entityManager) {
17	        this.entityManager = entityManager;
18	    }
19	
20	    public Map<String, Object> getOperationsSummary(LocalDateTime from, LocalDateTime to,
21	                                                      String orgId) {
22	        Map<String, Object> summary = new LinkedHashMap<>();
23	
24	        // Registration counts (filterable by org via event.organization_id)
25	        summary.put("totalRegistrations", countRegistrations(from, to, null, orgId));
26	        summary.put("approvedRegistrations", countRegistrations(from, to, "APPROVED", orgId));
27	        summary.put("cancelledRegistrations", countRegistrations(from, to, "CANCELLED", orgId));
28	        summary.put("waitlistedRegistrations", countRegistrations(from, to, "WAITLISTED", orgId));
29	
30	        // Claim counts
31	        summary.put("totalClaims", countClaims(from, to));
32	        summary.put("allowedClaims", countClaimsByResult(from, to, "ALLOWED"));
33	        summary.put("deniedClaims", countClaimsByResult(from, to, "DENIED_POLICY"));
34	
35	        // Order counts
36	        summary.put("totalOrders", countOrders(from, to));
37	        summary.put("deliveredOrders", countOrdersByStatus(from, to, "DELIVERED"));
38	        summary.put("redeemedOrders", countOrdersByStatus(from, to, "REDEEMED"));
39	
40	        // Completion rates
41	        long totalRegs = (long) summary.get("totalRegistrations");
42	        long approvedRegs = (long) summary.get("approvedRegistrations");
43	        summary.put("registrationApprovalRate",
44	                totalRegs > 0 ? (double) approvedRegs / totalRegs : 0.0);
45	
46	        long totalOrders = (long) summary.get("totalOrders");
47	        long completedOrders = (long) summary.get("deliveredOrders") + (long) summary.get("redeemedOrders");
48	        summary.put("orderCompletionRate",
49	                totalOrders > 0 ? (double) completedOrders / totalOrders : 0.0);
50	
51	        return summary;
52	    }
53	
54	    private long countRegistrations(LocalDateTime from, LocalDateTime to, String status,
55	                                     String orgId) {
56	        StringBuilder sql = new StringBuilder(
57	                "SELECT COUNT(*) FROM event_registration er");
58	        if (orgId != null) {
59	            sql.append(" JOIN event e ON er.event_id = e.id");
60	        }
61	        sql.append(" WHERE er.created_at BETWEEN :from AND :to");
62	        if (status != null) {
63	            sql.append(" AND er.status = :status");
64	        }
65	        if (orgId != null) {
66	            sql.append(" AND e.organization_id = :orgId");
67	        }
68	        Query query = entityManager.createNativeQuery(sql.toString());
69	        query.setParameter("from", from);
70	        query.setParameter("to", to);
71	        if (status != null) {
72	            query.setParameter("status", status);
73	        }
74	        if (orgId != null) {
75	            query.setParameter("orgId", orgId);
76	        }
77	        return ((Number) query.getSingleResult()).longValue();
78	    }
