71	    public ReportTemplate createTemplate(String name, String description, String metricIds,
72	                                          String filters, String format, Long actorId) {
73	        ReportTemplate template = new ReportTemplate();
74	        template.setName(name);
75	        template.setDescription(description);
76	        template.setMetricIds(metricIds);
77	        template.setDefaultFilters(filters);
78	        template.setOutputFormat(format != null ? format : "CSV");
