85	    @Transactional
86	    public ReportExecution executeReport(Long templateId, String filters, String format,
87	                                          Long actorId) {
88	        ReportTemplate template = templateRepository.findById(templateId)
89	                .orElseThrow(() -> new IllegalArgumentException("Template not found: " + templateId));
90	
91	        ReportExecution execution = new ReportExecution();
92	        execution.setTemplateId(templateId);
93	        execution.setFilters(filters);
94	        execution.setOutputFormat(format != null ? format : template.getOutputFormat());
95	        execution.setStatus("PENDING");
96	        execution.setExecutedBy(actorId);
97	        execution.setCreatedAt(LocalDateTime.now());
98	
99	        // Parse validated filters from the execution request
100	        Map<String, String> filterMap = parseFilters(filters != null ? filters : template.getDefaultFilters());
101	
102	        // Execute real metrics from the template's configured metric IDs
103	        List<String> headers = List.of("metric_name", "query", "result_value");
104	        List<List<String>> rows = new ArrayList<>();
105	
106	        String metricIdsStr = template.getMetricIds();
107	        if (metricIdsStr != null && !metricIdsStr.isBlank()) {
108	            for (String idStr : metricIdsStr.split(",")) {
109	                try {
110	                    Long metricId = Long.parseLong(idStr.trim());
111	                    metricRepository.findById(metricId).ifPresent(metric -> {
112	                        String queryTemplate = metric.getQueryTemplate();
113	                        try {
114	                            // Execute the metric query with validated filter bindings
115	                            Query query = entityManager.createNativeQuery(queryTemplate);
116	                            bindFilters(query, queryTemplate, filterMap);
117	                            Object result = query.getSingleResult();
118	                            rows.add(List.of(metric.getName(), queryTemplate, String.valueOf(result)));
119	                        } catch (Exception e) {
120	                            rows.add(List.of(metric.getName(), queryTemplate, "ERROR: " + e.getMessage()));
121	                        }
122	                    });
123	                } catch (NumberFormatException ignored) {
124	                    // skip invalid metric IDs
125	                }
126	            }
127	        }
128	
129	        if (rows.isEmpty()) {
130	            rows.add(List.of("(no metrics)", "", "0"));
131	        }
132	
133	        StringBuilder csv = new StringBuilder();
134	        csv.append(String.join(",", headers)).append("\n");
135	        for (List<String> row : rows) {
136	            csv.append(String.join(",", row)).append("\n");
137	        }
138	
139	        // Write to local file artifact
140	        String exportPath;
141	        String outputFormat = execution.getOutputFormat();
142	        if ("PDF".equalsIgnoreCase(outputFormat)) {
143	            exportPath = exportService.exportPdf("Report: " + template.getName(), headers, rows, "report-" + template.getId());
144	        } else {
145	            exportPath = exportService.exportCsv(csv.toString(), "report-" + template.getId());
146	        }
147	
148	        execution.setResultData(csv.toString());
149	        execution.setExportFilePath(exportPath);
150	        execution.setStatus("COMPLETED");
151	        execution.setCompletedAt(LocalDateTime.now());
152	
153	        ReportExecution saved = executionRepository.save(execution);
154	
155	        auditService.log(actorId, null, "REPORT_EXPORTED",
156	                "ReportExecution", saved.getId().toString(),
157	                null, "COMPLETED", null, null);
158	
159	        return saved;
160	    }
