171	    public Map<String, Object> getDataQuality(String domain, LocalDateTime from, LocalDateTime to) {
172	        Map<String, Object> quality = new LinkedHashMap<>();
173	
174	        if ("events".equals(domain) || domain == null) {
175	            quality.put("events_missing_description", countNullField("event", "description", from, to));
176	            quality.put("events_missing_location", countNullField("event", "location", from, to));
177	        }
178	
179	        if ("resources".equals(domain) || domain == null) {
180	            quality.put("resources_missing_description", countNullField("resource_item", "description", from, to));
181	        }
182	
183	        if ("rewards".equals(domain) || domain == null) {
184	            quality.put("rewards_missing_description", countNullField("reward_item", "description", from, to));
185	        }
186	
187	        // Duplicate detection counts
188	        if ("verification".equals(domain) || domain == null) {
189	            quality.put("credential_duplicates", countDuplicates(from, to));
190	        }
191	
192	        // Anomaly: accounts with excessive failed login attempts
193	        if ("accounts".equals(domain) || domain == null) {
194	            quality.put("accounts_with_high_failed_logins", countHighFailedLogins(from, to));
195	        }
196	
197	        return quality;
198	    }
