200	    private long countDuplicates(LocalDateTime from, LocalDateTime to) {
201	        String sql = "SELECT COUNT(*) FROM organization_credential_document " +
202	                "WHERE duplicate_flag = true AND created_at BETWEEN :from AND :to";
203	        Query query = entityManager.createNativeQuery(sql);
204	        query.setParameter("from", from);
205	        query.setParameter("to", to);
206	        return ((Number) query.getSingleResult()).longValue();
207	    }
208	
209	    private long countHighFailedLogins(LocalDateTime from, LocalDateTime to) {
210	        String sql = "SELECT COUNT(*) FROM account " +
211	                "WHERE failed_login_attempts >= 5 AND updated_at BETWEEN :from AND :to";
212	        Query query = entityManager.createNativeQuery(sql);
213	        query.setParameter("from", from);
214	        query.setParameter("to", to);
215	        return ((Number) query.getSingleResult()).longValue();
216	    }
