218	    private long countNullField(String table, String field, LocalDateTime from, LocalDateTime to) {
219	        String sql = "SELECT COUNT(*) FROM " + table +
220	                " WHERE " + field + " IS NULL AND created_at BETWEEN :from AND :to";
221	        Query query = entityManager.createNativeQuery(sql);
222	        query.setParameter("from", from);
223	        query.setParameter("to", to);
224	        return ((Number) query.getSingleResult()).longValue();
225	    }
