227	    /**
228	     * Parses a JSON filters string into a map. Returns empty map on null/invalid input.
229	     */
230	    private Map<String, String> parseFilters(String filtersJson) {
231	        if (filtersJson == null || filtersJson.isBlank()) {
232	            return Collections.emptyMap();
233	        }
234	        try {
235	            ObjectMapper mapper = new ObjectMapper();
236	            return mapper.readValue(filtersJson, new TypeReference<Map<String, String>>() {});
237	        } catch (Exception e) {
238	            return Collections.emptyMap();
239	        }
240	    }
