242	    /**
243	     * Binds filter values to named parameters found in the query template.
244	     * Supports :from, :to (as LocalDateTime), :organizationId, :stationId.
245	     */
246	    private void bindFilters(Query query, String queryTemplate, Map<String, String> filterMap) {
247	        if (queryTemplate.contains(":from") && filterMap.containsKey("from")) {
248	            query.setParameter("from", LocalDateTime.parse(filterMap.get("from") + (filterMap.get("from").contains("T") ? "" : "T00:00:00")));
249	        }
250	        if (queryTemplate.contains(":to") && filterMap.containsKey("to")) {
251	            query.setParameter("to", LocalDateTime.parse(filterMap.get("to") + (filterMap.get("to").contains("T") ? "" : "T23:59:59")));
252	        }
253	        if (queryTemplate.contains(":organizationId") && filterMap.containsKey("organizationId")) {
254	            query.setParameter("organizationId", filterMap.get("organizationId"));
255	        }
256	        if (queryTemplate.contains(":stationId") && filterMap.containsKey("stationId")) {
257	            query.setParameter("stationId", filterMap.get("stationId"));
258	        }
259	    }
