23	        this.encryptionService = encryptionService;
24	        this.basePath = basePath;
25	    }
26	
27	    /**
28	     * Encrypts content and writes to disk. Returns the relative file path.
29	     */
30	    public String store(byte[] content, String subDir) {
31	        byte[] encrypted = encryptionService.encryptBytes(content);
32	        String relativePath = subDir + "/" + UUID.randomUUID() + ".enc";
33	        Path fullPath = Path.of(basePath).resolve(relativePath);
34	        try {
35	            Files.createDirectories(fullPath.getParent());
36	            Files.write(fullPath, encrypted);
37	        } catch (IOException e) {
38	            throw new RuntimeException("Failed to store file", e);
39	        }
40	        return relativePath;
41	    }
42	
43	    /**
44	     * Reads an encrypted file from disk and returns the decrypted bytes.
45	     */
46	    public byte[] read(String relativePath) {
47	        Path fullPath = Path.of(basePath).resolve(relativePath);
48	        try {
49	            byte[] encrypted = Files.readAllBytes(fullPath);
50	            return encryptionService.decryptBytes(encrypted);
51	        } catch (IOException e) {
52	            throw new RuntimeException("Failed to read file", e);
53	        }
54	    }
55	
56	    /**
57	     * Computes SHA-256 hex checksum of the original (pre-encryption) content.
58	     */
59	    public String computeChecksum(byte[] content) {
60	        try {
61	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
62	            byte[] hash = digest.digest(content);
63	            return HexFormat.of().formatHex(hash);
64	        } catch (NoSuchAlgorithmException e) {
