38	                             String mode, String location, LocalDateTime startAt, LocalDateTime endAt,
39	                             Integer capacity, Boolean waitlistEnabled, Boolean manualReviewRequired,
40	                             String registrationFormSchema, String status, Long actorId, String actorRole) {
41	        // Validate org scope: actor must have approved ORG_OPERATOR membership for this org
