79	    @Transactional
80	    public Event updateEvent(Long id, String title, String description, String mode,
81	                             String location, LocalDateTime startAt, LocalDateTime endAt,
82	                             Integer capacity, Boolean waitlistEnabled, Boolean manualReviewRequired,
83	                             String registrationFormSchema, String status,
84	                             Long actorId, String actorRole) {
85	        Event event = eventRepository.findById(id)
86	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + id));
87	
88	        // Object-level authorization: only the event creator can update it
89	        if (!event.getCreatedBy().equals(actorId)) {
90	            throw new SecurityException("Cannot update an event you did not create");
91	        }
92	
93	        // Validate org scope for the event's organization
