120	    @Transactional
121	    public EventRegistration register(Long eventId, Long accountId, String formResponses) {
122	        Event event = eventRepository.findById(eventId)
123	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + eventId));
124	
125	        long approvedCount = registrationRepository.countByEventIdAndStatus(eventId, "APPROVED");
126	
127	        String regStatus;
128	        if (event.isManualReviewRequired()) {
129	            regStatus = "PENDING_REVIEW";
130	        } else if (approvedCount < event.getCapacity()) {
131	            regStatus = "APPROVED";
132	        } else if (event.isWaitlistEnabled()) {
133	            regStatus = "WAITLISTED";
134	        } else {
135	            throw new IllegalStateException("Event is full and waitlist is not enabled");
136	        }
137	
138	        EventRegistration reg = new EventRegistration();
139	        reg.setEventId(eventId);
140	        reg.setAccountId(accountId);
141	        reg.setStatus(regStatus);
142	        reg.setFormResponses(formResponses);
143	        reg.setCreatedAt(LocalDateTime.now());
144	        reg.setUpdatedAt(LocalDateTime.now());
145	
146	        EventRegistration saved = registrationRepository.save(reg);
147	
148	        auditService.log(accountId, null, "REGISTRATION_SUBMITTED",
149	                "EventRegistration", saved.getId().toString(),
150	                null, regStatus, null, null);
