155	    @Transactional
156	    public EventRegistration decideRegistration(Long regId, String decision, String note,
157	                                                 Long actorId, String actorRole) {
158	        if (!"APPROVE".equals(decision) && !"DENY".equals(decision)) {
159	            throw new IllegalArgumentException("Decision must be APPROVE or DENY");
160	        }
161	
162	        EventRegistration reg = registrationRepository.findById(regId)
163	                .orElseThrow(() -> new IllegalArgumentException("Registration not found: " + regId));
164	
165	        String beforeStatus = reg.getStatus();
166	
167	        if ("APPROVE".equals(decision)) {
168	            Event event = eventRepository.findById(reg.getEventId())
169	                    .orElseThrow(() -> new IllegalArgumentException("Event not found: " + reg.getEventId()));
170	            long approvedCount = registrationRepository.countByEventIdAndStatus(reg.getEventId(), "APPROVED");
171	            if (approvedCount >= event.getCapacity()) {
172	                throw new IllegalStateException("Event is at capacity, cannot approve registration");
173	            }
174	            reg.setStatus("APPROVED");
175	        } else {
176	            reg.setStatus("DENIED");
177	        }
178	
179	        reg.setReviewNote(note);
180	        reg.setReviewedBy(actorId);
181	        reg.setUpdatedAt(LocalDateTime.now());
182	
183	        EventRegistration saved = registrationRepository.save(reg);
184	
185	        auditService.log(actorId, actorRole, "REGISTRATION_DECIDED",
186	                "EventRegistration", saved.getId().toString(),
187	                beforeStatus, saved.getStatus(), decision, null);
188	
189	        return saved;
190	    }
