192	    @Transactional
193	    public EventRegistration cancelRegistration(Long regId, Long actorId) {
194	        EventRegistration reg = registrationRepository.findById(regId)
195	                .orElseThrow(() -> new IllegalArgumentException("Registration not found: " + regId));
196	
197	        if (!reg.getAccountId().equals(actorId)) {
198	            throw new SecurityException("Cannot cancel another user's registration");
199	        }
200	
201	        String beforeStatus = reg.getStatus();
202	        boolean wasApproved = "APPROVED".equals(beforeStatus);
203	
204	        reg.setStatus("CANCELLED");
205	        reg.setUpdatedAt(LocalDateTime.now());
206	        registrationRepository.save(reg);
207	
208	        auditService.log(actorId, null, "REGISTRATION_CANCELLED",
209	                "EventRegistration", reg.getId().toString(),
210	                beforeStatus, "CANCELLED", null, null);
211	
212	        // Auto-promote oldest waitlisted entry if the cancelled reg was approved
213	        if (wasApproved) {
214	            List<EventRegistration> waitlisted = registrationRepository
215	                    .findByEventIdAndStatus(reg.getEventId(), "WAITLISTED");
216	            if (!waitlisted.isEmpty()) {
217	                // Find oldest by createdAt
218	                EventRegistration oldest = waitlisted.stream()
219	                        .min((a, b) -> a.getCreatedAt().compareTo(b.getCreatedAt()))
220	                        .get();
221	                oldest.setStatus("APPROVED");
222	                oldest.setUpdatedAt(LocalDateTime.now());
223	                registrationRepository.save(oldest);
224	
225	                auditService.log(actorId, null, "REGISTRATION_AUTO_PROMOTED",
226	                        "EventRegistration", oldest.getId().toString(),
227	                        "WAITLISTED", "APPROVED", "WAITLIST_PROMOTION", null);
228	            }
229	        }
230	
231	        return reg;
232	    }
233	
234	    public List<EventRegistration> getPendingRegistrations() {
235	        return registrationRepository.findByStatus("PENDING_REVIEW");
236	    }
