242	    private void validateOrganizationScope(Long actorId, String organizationId, String actorRole) {
243	        // ADMINs bypass org scope checks
244	        if ("ADMIN".equals(actorRole)) {
245	            return;
246	        }
247	        boolean hasScope = roleMembershipRepository.existsByAccountIdAndRoleTypeAndScopeIdAndStatus(
248	                actorId, "ORG_OPERATOR", organizationId, RoleMembership.RoleMembershipStatus.APPROVED);
249	        if (!hasScope) {
250	            throw new SecurityException(
251	                    "Not authorized for organization: " + organizationId);
252	        }
253	    }
