255	    /**
256	     * Exports event roster as a local file artifact (CSV or PDF).
257	     * Returns the relative file path for retrieval.
258	     */
259	    public String exportRoster(Long eventId, String format, Long actorId, String actorRole) {
260	        List<EventRegistration> approved = registrationRepository.findByEventIdAndStatus(eventId, "APPROVED");
261	        Event event = eventRepository.findById(eventId)
262	                .orElseThrow(() -> new IllegalArgumentException("Event not found: " + eventId));
263	
264	        List<String> headers = List.of("Registration ID", "Event ID", "Account ID", "Status", "Registered At");
265	        List<List<String>> rows = new ArrayList<>();
266	        StringBuilder csv = new StringBuilder();
267	        csv.append(String.join(",", headers)).append("\n");
268	
269	        for (EventRegistration reg : approved) {
270	            List<String> row = List.of(
271	                    reg.getId().toString(),
272	                    reg.getEventId().toString(),
273	                    reg.getAccountId().toString(),
274	                    reg.getStatus(),
275	                    reg.getCreatedAt().toString());
276	            rows.add(row);
277	            csv.append(String.join(",", row)).append("\n");
278	        }
279	
280	        String exportPath;
281	        if ("PDF".equalsIgnoreCase(format)) {
282	            exportPath = exportService.exportPdf("Roster: " + event.getTitle(), headers, rows, "roster-" + eventId);
283	        } else {
284	            exportPath = exportService.exportCsv(csv.toString(), "roster-" + eventId);
285	        }
286	
287	        auditService.log(actorId, actorRole, "ROSTER_EXPORTED",
288	                "Event", eventId.toString(),
289	                null, exportPath, format, null);
290	
291	        return exportPath;
292	    }
