174	    public Map<String, Object> getDataQuality(String domain, LocalDateTime from, LocalDateTime to) {
175	        Map<String, Object> quality = new LinkedHashMap<>();
176	
177	        if ("events".equals(domain) || domain == null) {
178	            quality.put("events_missing_description", countNullField("event", "description", from, to));
179	            quality.put("events_missing_location", countNullField("event", "location", from, to));
180	        }
181	
182	        if ("resources".equals(domain) || domain == null) {
183	            quality.put("resources_missing_description", countNullField("resource_item", "description", from, to));
184	        }
185	
186	        if ("rewards".equals(domain) || domain == null) {
187	            quality.put("rewards_missing_description", countNullField("reward_item", "description", from, to));
188	        }
189	
190	        // Duplicate detection counts
191	        if ("verification".equals(domain) || domain == null) {
192	            quality.put("credential_duplicates", countDuplicates(from, to));
193	        }
194	
195	        // Anomaly: accounts with excessive failed login attempts
196	        if ("accounts".equals(domain) || domain == null) {
197	            quality.put("accounts_with_high_failed_logins", countHighFailedLogins(from, to));
198	        }
199	
200	        return quality;
201	    }
