203	    private long countDuplicates(LocalDateTime from, LocalDateTime to) {
204	        String sql = "SELECT COUNT(*) FROM organization_credential_document " +
205	                "WHERE duplicate_flag = true AND created_at BETWEEN :from AND :to";
206	        Query query = entityManager.createNativeQuery(sql);
207	        query.setParameter("from", from);
208	        query.setParameter("to", to);
209	        return ((Number) query.getSingleResult()).longValue();
210	    }
211	
212	    private long countHighFailedLogins(LocalDateTime from, LocalDateTime to) {
213	        String sql = "SELECT COUNT(*) FROM account " +
214	                "WHERE failed_login_attempts >= 5 AND updated_at BETWEEN :from AND :to";
215	        Query query = entityManager.createNativeQuery(sql);
216	        query.setParameter("from", from);
217	        query.setParameter("to", to);
218	        return ((Number) query.getSingleResult()).longValue();
219	    }
