221	    private long countNullField(String table, String field, LocalDateTime from, LocalDateTime to) {
222	        String sql = "SELECT COUNT(*) FROM " + table +
223	                " WHERE " + field + " IS NULL AND created_at BETWEEN :from AND :to";
224	        Query query = entityManager.createNativeQuery(sql);
225	        query.setParameter("from", from);
226	        query.setParameter("to", to);
