75	        List<RoleMembership> approved = roleMembershipRepository.findByAccountIdAndStatus(
76	                accountId, RoleMembership.RoleMembershipStatus.APPROVED);
77	
78	        RoleMembership match = null;
79	        for (RoleMembership m : approved) {
80	            if (m.getRoleType().equals(role) && Objects.equals(m.getScopeId(), scopeId)) {
81	                match = m;
