116	        // Service-layer enforcement: only ADMIN role can decide role approvals
117	        if (!"ADMIN".equals(actorRole)) {
118	            throw new SecurityException("Only ADMIN can approve or deny role requests");
119	        }
120	        if (!"APPROVE".equals(decision) && !"DENY".equals(decision)) {
121	            throw new IllegalArgumentException("Decision must be APPROVE or DENY");
122	        }
123	
124	        RoleMembership membership = roleMembershipRepository.findById(membershipId)
125	                .orElseThrow(() -> new IllegalArgumentException("Role membership not found: " + membershipId));
126	
127	        // On approval, check verification prerequisites for the requested role
128	        if ("APPROVE".equals(decision)) {
129	            checkVerificationPrerequisites(membership.getAccountId(), membership.getRoleType());
