133	        RoleMembership.RoleMembershipStatus newStatus = "APPROVE".equals(decision)
134	                ? RoleMembership.RoleMembershipStatus.APPROVED
135	                : RoleMembership.RoleMembershipStatus.DENIED;
136	
137	        membership.setStatus(newStatus);
138	        membership.setUpdatedAt(LocalDateTime.now());
139	
140	        RoleMembership saved = roleMembershipRepository.save(membership);
141	
142	        auditService.log(actorId, actorRole, "ROLE_DECISION",
143	                "RoleMembership", saved.getId().toString(),
144	                beforeStatus, newStatus.name(), decision, null);
145	
146	        return saved;
147	    }
