99	
100	        // Session fixation protection: invalidate any existing session before creating a new one
101	        HttpSession existingSession = httpRequest.getSession(false);
102	        if (existingSession != null) {
103	            existingSession.invalidate();
104	        }
105	
106	        // Create fresh session — blacklisted users get a constrained session
107	        // that only allows appeal submission (enforced by BlacklistEnforcementFilter)
108	        HttpSession httpSession = httpRequest.getSession(true);
109	        httpSession.setAttribute(SESSION_ACCOUNT_KEY, session);
110	
111	        if ("BLACKLISTED".equals(session.accountStatus())) {
112	            // Return 423 per API spec, but the session cookie IS set so appeal endpoints work
113	            BlacklistRecord record = blacklistRecordRepository
114	                    .findTopByAccountIdOrderByCreatedAtDesc(session.accountId())
115	                    .orElse(null);
116	
117	            ErrorResponse error = new ErrorResponse(
118	                    "ACCOUNT_BLACKLISTED",
119	                    "Account has been blacklisted. You may submit an appeal.",
120	                    List.of(),
121	                    UUID.randomUUID().toString(),
122	                    Instant.now()
123	            );
124	            return ResponseEntity.status(423).body(error);
125	        }
126	
