    public List<RewardOrder> listOrders(Long actorId, boolean isAdmin) {
        if (isAdmin) {
            return orderRepository.findAll();
        }
        // ORG_OPERATOR: see orders for rewards created by accounts in same org scope
        List<String> orgIds = getActorOrgScopes(actorId);
        if (orgIds.isEmpty()) return List.of();
        List<Long> orgAccountIds = roleMembershipRepository.findByStatus(RoleMembership.RoleMembershipStatus.APPROVED)
