                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()) && orgIds.contains(m.getScopeId()))
                .map(RoleMembership::getAccountId)
                .distinct()
                .toList();
        if (orgAccountIds.isEmpty()) return List.of();
        return orderRepository.findByRewardCreatorIn(orgAccountIds);
    }

