20	    private static final Pattern STATE_PATTERN = Pattern.compile("^[A-Z]{2}$");
21	
22	    private static final Map<String, Set<String>> PHYSICAL_TRANSITIONS = Map.of(
23	            "ORDERED", Set.of("ALLOCATED"),
