64	    public List<RewardOrder> listOrders(Long actorId, boolean isAdmin) {
65	        if (isAdmin) {
66	            return orderRepository.findAll();
67	        }
68	        // ORG_OPERATOR: see orders for rewards created by accounts in same org scope
69	        List<String> orgIds = getActorOrgScopes(actorId);
70	        if (orgIds.isEmpty()) return List.of();
71	        List<Long> orgAccountIds = roleMembershipRepository.findByStatus(RoleMembership.RoleMembershipStatus.APPROVED)
72	                .stream()
73	                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()) && orgIds.contains(m.getScopeId()))
74	                .map(RoleMembership::getAccountId)
75	                .distinct()
76	                .toList();
77	        if (orgAccountIds.isEmpty()) return List.of();
78	        return orderRepository.findByRewardCreatorIn(orgAccountIds);
