125	    @Transactional
126	    public ShippingAddress createAddress(Long accountId, String line1, String line2,
127	                                          String city, String state, String zip) {
128	        if (!STATE_PATTERN.matcher(state).matches()) {
129	            throw new IllegalArgumentException("State must be a 2-character uppercase code");
130	        }
131	        if (!ZIP_PATTERN.matcher(zip).matches()) {
132	            throw new IllegalArgumentException("Zip code must be in 5-digit or 5+4 format");
133	        }
134	
135	        // Auto-primary: first address for an account becomes primary
136	        List<ShippingAddress> existing = addressRepository.findByAccountId(accountId);
137	        boolean shouldBePrimary = existing.isEmpty();
138	
139	        ShippingAddress addr = new ShippingAddress();
140	        addr.setAccountId(accountId);
141	        addr.setAddressLine1Encrypted(encryptionService.encrypt(line1));
142	        addr.setAddressLine2Encrypted(line2 != null ? encryptionService.encrypt(line2) : null);
143	        addr.setCity(city);
144	        addr.setStateCode(state);
145	        addr.setZipCode(zip);
146	        addr.setPrimary(shouldBePrimary);
147	        addr.setCreatedAt(LocalDateTime.now());
148	
149	        ShippingAddress saved = addressRepository.save(addr);
150	
151	        auditService.log(accountId, null, "ADDRESS_CREATED",
152	                "ShippingAddress", saved.getId().toString(),
153	                null, shouldBePrimary ? "PRIMARY" : null, null, null);
154	
155	        return saved;
156	    }
