158	    @Transactional
159	    public ShippingAddress setPrimaryAddress(Long accountId, Long addressId) {
160	        ShippingAddress target = addressRepository.findById(addressId)
161	                .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
162	        if (!target.getAccountId().equals(accountId)) {
163	            throw new SecurityException("Cannot modify another user's address");
164	        }
165	
166	        // Clear existing primary
167	        List<ShippingAddress> all = addressRepository.findByAccountId(accountId);
168	        for (ShippingAddress a : all) {
169	            if (a.isPrimary()) {
170	                a.setPrimary(false);
171	                addressRepository.save(a);
172	            }
173	        }
174	
175	        target.setPrimary(true);
176	        ShippingAddress saved = addressRepository.save(target);
177	
178	        auditService.log(accountId, null, "ADDRESS_SET_PRIMARY",
179	                "ShippingAddress", saved.getId().toString(),
180	                null, "PRIMARY", null, null);
181	
182	        return saved;
183	    }
