190	    public RewardOrder placeOrder(Long rewardId, Long accountId, Integer quantity,
191	                                   String fulfillmentType, Long addressId) {
192	        // Validate address ownership if shipping
193	        if (addressId != null) {
194	            ShippingAddress addr = addressRepository.findById(addressId)
195	                    .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
196	            if (!addr.getAccountId().equals(accountId)) {
197	                throw new SecurityException("Cannot use another user's shipping address");
198	            }
199	        }
200	
201	        RewardItem reward = rewardRepository.findById(rewardId)
202	                .orElseThrow(() -> new IllegalArgumentException("Reward not found: " + rewardId));
203	
204	        int qty = quantity != null ? quantity : 1;
205	
206	        // Check per-user limit
207	        long existingOrders = orderRepository.countByRewardIdAndAccountId(rewardId, accountId);
208	        if (existingOrders + qty > reward.getPerUserLimit()) {
209	            throw new IllegalStateException("Per-user limit exceeded for this reward");
210	        }
211	
212	        // Check inventory
213	        if (reward.getInventoryCount() < qty) {
214	            throw new IllegalStateException("Insufficient inventory for this reward");
215	        }
216	
217	        // Decrement inventory
218	        reward.setInventoryCount(reward.getInventoryCount() - qty);
219	        reward.setUpdatedAt(LocalDateTime.now());
220	        rewardRepository.save(reward);
221	
222	        RewardOrder order = new RewardOrder();
223	        order.setRewardId(rewardId);
224	        order.setAccountId(accountId);
225	        order.setQuantity(qty);
226	        order.setFulfillmentType(fulfillmentType != null ? fulfillmentType : reward.getFulfillmentType());
227	        order.setShippingAddressId(addressId);
228	        order.setStatus("ORDERED");
229	        order.setStatusChangedAt(LocalDateTime.now());
230	        order.setCreatedAt(LocalDateTime.now());
231	        order.setUpdatedAt(LocalDateTime.now());
232	
233	        RewardOrder saved = orderRepository.save(order);
234	
