242	    @Transactional
243	    public RewardOrder transitionOrder(Long orderId, String toState, String note,
244	                                        Long actorId, String actorRole) {
245	        RewardOrder order = orderRepository.findById(orderId)
246	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
247	
248	        String beforeState = order.getStatus();
249	        Map<String, Set<String>> transitions = "VOUCHER".equals(order.getFulfillmentType())
250	                ? VOUCHER_TRANSITIONS : PHYSICAL_TRANSITIONS;
251	
252	        Set<String> allowedNext = transitions.get(beforeState);
253	        if (allowedNext == null || !allowedNext.contains(toState)) {
254	            throw new IllegalStateException(
255	                    "Invalid transition from " + beforeState + " to " + toState);
256	        }
257	
258	        order.setStatus(toState);
259	        order.setStatusChangedAt(LocalDateTime.now());
260	        if (note != null) order.setNote(note);
261	        order.setUpdatedAt(LocalDateTime.now());
262	
263	        RewardOrder saved = orderRepository.save(order);
264	
265	        auditService.log(actorId, actorRole, "ORDER_TRANSITIONED",
266	                "RewardOrder", saved.getId().toString(),
267	                beforeState, toState, null, null);
268	
269	        return saved;
270	    }
271	
272	    @Transactional
273	    public RewardOrder setTracking(Long orderId, String trackingNumber) {
274	        RewardOrder order = orderRepository.findById(orderId)
275	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
276	        if (!"SHIPPED".equals(order.getStatus())) {
277	            throw new IllegalStateException("Tracking can only be set for SHIPPED orders");
278	        }
279	        order.setTrackingNumber(trackingNumber);
280	        order.setUpdatedAt(LocalDateTime.now());
281	        return orderRepository.save(order);
282	    }
