284	    @Transactional
285	    public RewardOrder issueVoucher(Long orderId, String voucherCode) {
286	        RewardOrder order = orderRepository.findById(orderId)
287	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
288	        if (!"VOUCHER_ISSUED".equals(order.getStatus())) {
289	            throw new IllegalStateException("Voucher can only be issued for VOUCHER_ISSUED status orders");
290	        }
291	        order.setVoucherCode(voucherCode);
292	        order.setUpdatedAt(LocalDateTime.now());
293	        return orderRepository.save(order);
294	    }
295	
296	    @Transactional
297	    public FulfillmentException createException(Long orderId, String reasonCode,
298	                                                 String description, Long actorId) {
299	        FulfillmentException exception = new FulfillmentException();
300	        exception.setOrderId(orderId);
301	        exception.setReasonCode(reasonCode);
302	        exception.setDescription(description);
303	        exception.setStatus("OPEN");
304	        exception.setCreatedBy(actorId);
305	        exception.setCreatedAt(LocalDateTime.now());
306	        exception.setUpdatedAt(LocalDateTime.now());
307	
308	        FulfillmentException saved = exceptionRepository.save(exception);
309	
310	        auditService.log(actorId, null, "EXCEPTION_CREATED",
311	                "FulfillmentException", saved.getId().toString(),
312	                null, "OPEN", reasonCode, null);
313	
314	        return saved;
315	    }
316	
317	    @Transactional
318	    public FulfillmentException transitionException(Long exceptionId, String toState,
319	                                                     Long actorId, String actorRole) {
320	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
321	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
322	
323	        String beforeState = exc.getStatus();
324	        Set<String> allowedNext = EXCEPTION_TRANSITIONS.get(beforeState);
325	        if (allowedNext == null || !allowedNext.contains(toState)) {
326	            throw new IllegalStateException(
327	                    "Invalid transition from " + beforeState + " to " + toState);
328	        }
329	
330	        exc.setStatus(toState);
331	        if ("RESOLVED".equals(toState) || "REJECTED".equals(toState)) {
332	            exc.setResolvedBy(actorId);
333	        }
334	        exc.setUpdatedAt(LocalDateTime.now());
335	
336	        FulfillmentException saved = exceptionRepository.save(exc);
337	
338	        auditService.log(actorId, actorRole, "EXCEPTION_TRANSITIONED",
339	                "FulfillmentException", saved.getId().toString(),
340	                beforeState, toState, null, null);
341	
342	        return saved;
343	    }
344	
345	    @Transactional
346	    public FulfillmentException reopenException(Long exceptionId, String reasonCode, String note,
347	                                                 Long actorId, String actorRole) {
348	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
349	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
350	
351	        if (!"RESOLVED".equals(exc.getStatus()) && !"REJECTED".equals(exc.getStatus())) {
352	            throw new IllegalStateException("Can only reopen from RESOLVED or REJECTED state");
353	        }
354	
355	        String beforeState = exc.getStatus();
356	        exc.setStatus("OPEN");
357	        exc.setReopenReason(note);
358	        exc.setSupervisorApproval(true);
359	        exc.setResolvedBy(null);
360	        exc.setUpdatedAt(LocalDateTime.now());
361	
362	        FulfillmentException saved = exceptionRepository.save(exc);
363	
364	        auditService.log(actorId, actorRole, "EXCEPTION_REOPENED",
365	                "FulfillmentException", saved.getId().toString(),
366	                beforeState, "OPEN", reasonCode, null);
367	
368	        return saved;
369	    }
370	
371	    public List<RewardOrder> getOverdueOrders() {
372	        LocalDateTime sevenDaysAgo = LocalDateTime.now().minusDays(7);
373	        return orderRepository.findOverdueOrders(List.of("PACKED", "SHIPPED"), sevenDaysAgo);
374	    }
375	}
