10	import java.util.List;
11	import java.util.Map;
12	import java.util.Set;
13	
14	@Service
15	public class WorkOrderService {
16	
17	    private static final Map<String, Set<String>> WO_TRANSITIONS = Map.of(
18	            "NEW_ALERT", Set.of("ACKNOWLEDGED"),
19	            "ACKNOWLEDGED", Set.of("DISPATCHED"),
20	            "DISPATCHED", Set.of("IN_PROGRESS"),
21	            "IN_PROGRESS", Set.of("RESOLVED"),
22	            "RESOLVED", Set.of("CLOSED")
23	    );
24	
25	    private final WorkOrderRepository workOrderRepository;
26	    private final WorkOrderNoteRepository noteRepository;
27	    private final WorkOrderPhotoRepository photoRepository;
28	    private final PostIncidentReviewRepository pirRepository;
29	    private final FileStorageService fileStorageService;
30	    private final AuditService auditService;
31	
32	    public WorkOrderService(WorkOrderRepository workOrderRepository,
33	                            WorkOrderNoteRepository noteRepository,
34	                            WorkOrderPhotoRepository photoRepository,
35	                            PostIncidentReviewRepository pirRepository,
36	                            FileStorageService fileStorageService,
37	                            AuditService auditService) {
38	        this.workOrderRepository = workOrderRepository;
39	        this.noteRepository = noteRepository;
40	        this.photoRepository = photoRepository;
41	        this.pirRepository = pirRepository;
42	        this.fileStorageService = fileStorageService;
43	        this.auditService = auditService;
44	    }
45	
46	    @Transactional
47	    public WorkOrder createWorkOrder(String title, String description, String severity,
48	                                      Long alertEventId, Long actorId) {
49	        WorkOrder wo = new WorkOrder();
50	        wo.setTitle(title);
51	        wo.setDescription(description);
52	        wo.setSeverity(severity != null ? severity : "MEDIUM");
53	        wo.setAlertEventId(alertEventId);
54	        wo.setStatus("NEW_ALERT");
55	        wo.setCreatedBy(actorId);
56	        wo.setCreatedAt(LocalDateTime.now());
57	        wo.setUpdatedAt(LocalDateTime.now());
58	
59	        WorkOrder saved = workOrderRepository.save(wo);
60	
61	        auditService.log(actorId, null, "WORK_ORDER_CREATED",
62	                "WorkOrder", saved.getId().toString(),
63	                null, "NEW_ALERT", null, null);
64	
65	        return saved;
66	    }
67	
68	    @Transactional
69	    public WorkOrder transitionWorkOrder(Long id, String toStatus, Long actorId) {
70	        WorkOrder wo = workOrderRepository.findById(id)
71	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + id));
72	
73	        String beforeStatus = wo.getStatus();
74	        Set<String> allowedNext = WO_TRANSITIONS.get(beforeStatus);
75	        if (allowedNext == null || !allowedNext.contains(toStatus)) {
76	            throw new IllegalStateException(
77	                    "Invalid transition from " + beforeStatus + " to " + toStatus);
78	        }
79	
80	        wo.setStatus(toStatus);
81	        wo.setUpdatedAt(LocalDateTime.now());
82	
83	        // Record first_response_at on first ACKNOWLEDGED
84	        if ("ACKNOWLEDGED".equals(toStatus) && wo.getFirstResponseAt() == null) {
85	            wo.setFirstResponseAt(LocalDateTime.now());
86	        }
87	
88	        // Record closed_at on CLOSED
89	        if ("CLOSED".equals(toStatus)) {
90	            wo.setClosedAt(LocalDateTime.now());
91	        }
92	
93	        WorkOrder saved = workOrderRepository.save(wo);
94	
95	        auditService.log(actorId, null, "WORK_ORDER_TRANSITIONED",
96	                "WorkOrder", saved.getId().toString(),
97	                beforeStatus, toStatus, null, null);
98	
99	        return saved;
100	    }
101	
102	    @Transactional
103	    public WorkOrder assignWorkOrder(Long id, Long assigneeId, Long actorId) {
104	        WorkOrder wo = workOrderRepository.findById(id)
105	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + id));
106	
107	        if (!"DISPATCHED".equals(wo.getStatus())) {
108	            throw new IllegalStateException("Can only assign work orders in DISPATCHED status");
109	        }
110	
111	        wo.setAssignedTo(assigneeId);
112	        wo.setUpdatedAt(LocalDateTime.now());
113	
114	        WorkOrder saved = workOrderRepository.save(wo);
115	
116	        auditService.log(actorId, null, "WORK_ORDER_ASSIGNED",
117	                "WorkOrder", saved.getId().toString(),
118	                null, null, null, null);
119	
120	        return saved;
121	    }
122	
123	    @Transactional
124	    public WorkOrderNote addNote(Long workOrderId, Long authorId, String content) {
125	        workOrderRepository.findById(workOrderId)
126	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + workOrderId));
127	
128	        WorkOrderNote note = new WorkOrderNote();
129	        note.setWorkOrderId(workOrderId);
130	        note.setAuthorId(authorId);
131	        note.setContent(content);
132	        note.setCreatedAt(LocalDateTime.now());
133	
134	        return noteRepository.save(note);
135	    }
136	
137	    @Transactional
138	    public WorkOrderPhoto addPhoto(Long workOrderId, Long uploaderId, byte[] fileBytes,
139	                                    String fileName, String contentType) {
140	        workOrderRepository.findById(workOrderId)
141	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + workOrderId));
142	
143	        String filePath = fileStorageService.store(fileBytes, "work-order-photos");
144	
145	        WorkOrderPhoto photo = new WorkOrderPhoto();
146	        photo.setWorkOrderId(workOrderId);
147	        photo.setFilePath(filePath);
148	        photo.setFileName(fileName);
149	        photo.setContentType(contentType);
150	        photo.setUploadedBy(uploaderId);
151	        photo.setCreatedAt(LocalDateTime.now());
152	
153	        return photoRepository.save(photo);
154	    }
155	
156	    @Transactional
157	    public PostIncidentReview createPostIncidentReview(Long workOrderId, String summary,
158	                                                        String lessons, String actions,
159	                                                        Long actorId) {
160	        workOrderRepository.findById(workOrderId)
161	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + workOrderId));
162	
163	        if (pirRepository.findByWorkOrderId(workOrderId).isPresent()) {
164	            throw new IllegalStateException("Post-incident review already exists for work order: " + workOrderId);
165	        }
166	
167	        PostIncidentReview pir = new PostIncidentReview();
168	        pir.setWorkOrderId(workOrderId);
169	        pir.setSummary(summary);
170	        pir.setLessonsLearned(lessons);
171	        pir.setCorrectiveActions(actions);
172	        pir.setReviewedBy(actorId);
173	        pir.setCreatedAt(LocalDateTime.now());
174	
175	        PostIncidentReview saved = pirRepository.save(pir);
176	
177	        auditService.log(actorId, null, "POST_INCIDENT_REVIEW_CREATED",
178	                "PostIncidentReview", saved.getId().toString(),
179	                null, null, null, null);
180	
181	        return saved;
182	    }
183	
184	    public WorkOrder getWorkOrder(Long id) {
185	        return workOrderRepository.findById(id)
186	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + id));
187	    }
188	
189	    public Long computeFirstResponseSeconds(WorkOrder wo) {
190	        if (wo.getFirstResponseAt() == null || wo.getCreatedAt() == null) return null;
191	        return Duration.between(wo.getCreatedAt(), wo.getFirstResponseAt()).getSeconds();
192	    }
193	
194	    public Long computeTimeToCloseSeconds(WorkOrder wo) {
195	        if (wo.getClosedAt() == null || wo.getCreatedAt() == null) return null;
196	        return Duration.between(wo.getCreatedAt(), wo.getClosedAt()).getSeconds();
197	    }
198	
199	    public List<WorkOrder> listWorkOrders(String statusFilter, Long actorId, boolean isAdmin) {
200	        if (isAdmin) {
201	            if (statusFilter != null && !statusFilter.isBlank()) {
202	                return workOrderRepository.findByStatus(statusFilter);
203	            }
204	            return workOrderRepository.findAll();
205	        }
206	        // Non-admin: scoped to work orders they created
207	        if (statusFilter != null && !statusFilter.isBlank()) {
208	            return workOrderRepository.findByCreatedByAndStatus(actorId, statusFilter);
209	        }
210	        return workOrderRepository.findByCreatedBy(actorId);
211	    }
212	}
