import com.croh.account.RoleMembership;
import com.croh.account.RoleMembershipRepository;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * Reusable helper for organization-scope authorization checks.
 * Resolves an actor's allowed org scope IDs from approved ORG_OPERATOR
 * role memberships and enforces scope boundaries.
 */
@Service
public class OrgScopeService {

    private final RoleMembershipRepository roleMembershipRepository;

    public OrgScopeService(RoleMembershipRepository roleMembershipRepository) {
        this.roleMembershipRepository = roleMembershipRepository;
    }

    /**
     * Returns the list of organization scope IDs the actor has approved
     * ORG_OPERATOR memberships for.
     */
    public List<String> getOrgScopes(Long actorId) {
        return roleMembershipRepository.findByAccountIdAndStatus(
                        actorId, RoleMembership.RoleMembershipStatus.APPROVED).stream()
                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()))
                .map(RoleMembership::getScopeId)
                .filter(s -> s != null)
                .toList();
    }

    /**
     * Returns the account IDs of all users who hold an approved ORG_OPERATOR
     * membership in any of the given org scopes.
     */
    public List<Long> getAccountIdsInOrgScopes(List<String> orgScopeIds) {
        if (orgScopeIds.isEmpty()) return List.of();
        return roleMembershipRepository.findByStatus(RoleMembership.RoleMembershipStatus.APPROVED)
                .stream()
                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()) && orgScopeIds.contains(m.getScopeId()))
                .map(RoleMembership::getAccountId)
                .distinct()
                .toList();
    }

    /**
     * Checks whether the actor is authorized for the organization that owns
     * the object identified by {@code objectCreatorId}. ADMINs always pass.
     * ORG_OPERATORs pass only if the creator belongs to one of the actor's
     * org scopes.
     *
     * @throws SecurityException if the actor is not authorized
     */
    public void enforceCreatorOrgScope(Long actorId, String actorRole, Long objectCreatorId) {
        if ("ADMIN".equals(actorRole)) {
            return;
        }
        List<String> actorScopes = getOrgScopes(actorId);
        List<Long> allowedAccountIds = getAccountIdsInOrgScopes(actorScopes);
        if (!allowedAccountIds.contains(objectCreatorId)) {
            throw new SecurityException("Not authorized to access this object across organization scope");
        }
    }
}
