1	package com.croh.security;
2	
3	import com.croh.account.RoleMembership;
4	import com.croh.account.RoleMembershipRepository;
5	import org.springframework.stereotype.Service;
6	
7	import java.util.List;
8	
9	/**
10	 * Reusable helper for organization-scope authorization checks.
11	 * Resolves an actor's allowed org scope IDs from approved ORG_OPERATOR
12	 * role memberships and enforces scope boundaries.
13	 */
14	@Service
15	public class OrgScopeService {
16	
17	    private final RoleMembershipRepository roleMembershipRepository;
18	
19	    public OrgScopeService(RoleMembershipRepository roleMembershipRepository) {
20	        this.roleMembershipRepository = roleMembershipRepository;
21	    }
22	
23	    /**
24	     * Returns the list of organization scope IDs the actor has approved
25	     * ORG_OPERATOR memberships for.
26	     */
27	    public List<String> getOrgScopes(Long actorId) {
28	        return roleMembershipRepository.findByAccountIdAndStatus(
29	                        actorId, RoleMembership.RoleMembershipStatus.APPROVED).stream()
30	                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()))
31	                .map(RoleMembership::getScopeId)
32	                .filter(s -> s != null)
33	                .toList();
34	    }
35	
36	    /**
37	     * Returns the account IDs of all users who hold an approved ORG_OPERATOR
38	     * membership in any of the given org scopes.
39	     */
40	    public List<Long> getAccountIdsInOrgScopes(List<String> orgScopeIds) {
41	        if (orgScopeIds.isEmpty()) return List.of();
42	        return roleMembershipRepository.findByStatus(RoleMembership.RoleMembershipStatus.APPROVED)
43	                .stream()
44	                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()) && orgScopeIds.contains(m.getScopeId()))
45	                .map(RoleMembership::getAccountId)
46	                .distinct()
47	                .toList();
48	    }
49	
50	    /**
51	     * Checks whether the actor is authorized for the organization that owns
52	     * the object identified by {@code objectCreatorId}. ADMINs always pass.
53	     * ORG_OPERATORs pass only if the creator belongs to one of the actor's
54	     * org scopes.
55	     *
56	     * @throws SecurityException if the actor is not authorized
57	     */
58	    public void enforceCreatorOrgScope(Long actorId, String actorRole, Long objectCreatorId) {
59	        if ("ADMIN".equals(actorRole)) {
60	            return;
61	        }
62	        List<String> actorScopes = getOrgScopes(actorId);
63	        List<Long> allowedAccountIds = getAccountIdsInOrgScopes(actorScopes);
64	        if (!allowedAccountIds.contains(objectCreatorId)) {
65	            throw new SecurityException("Not authorized to access this object across organization scope");
66	        }
67	    }
68	}
