19	    private static final Pattern STATE_PATTERN = Pattern.compile("^[A-Z]{2}$");
20	
21	    private static final Map<String, Set<String>> PHYSICAL_TRANSITIONS = Map.of(
22	            "ORDERED", Set.of("ALLOCATED"),
23	            "ALLOCATED", Set.of("PACKED"),
24	            "PACKED", Set.of("SHIPPED"),
