34	    private static final Map<String, Set<String>> EXCEPTION_TRANSITIONS = Map.of(
35	            "OPEN", Set.of("UNDER_REVIEW"),
36	            "UNDER_REVIEW", Set.of("RESOLVED", "REJECTED")
37	    );
