152	    @Transactional
153	    public ShippingAddress setPrimaryAddress(Long accountId, Long addressId) {
154	        ShippingAddress target = addressRepository.findById(addressId)
155	                .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
156	        if (!target.getAccountId().equals(accountId)) {
157	            throw new SecurityException("Cannot modify another user's address");
158	        }
159	
160	        // Clear existing primary
161	        List<ShippingAddress> all = addressRepository.findByAccountId(accountId);
162	        for (ShippingAddress a : all) {
163	            if (a.isPrimary()) {
164	                a.setPrimary(false);
165	                addressRepository.save(a);
166	            }
167	        }
168	
169	        target.setPrimary(true);
170	        ShippingAddress saved = addressRepository.save(target);
171	
172	        auditService.log(accountId, null, "ADDRESS_SET_PRIMARY",
173	                "ShippingAddress", saved.getId().toString(),
174	                null, "PRIMARY", null, null);
175	
176	        return saved;
