183	    @Transactional
184	    public RewardOrder placeOrder(Long rewardId, Long accountId, Integer quantity,
185	                                   String fulfillmentType, Long addressId) {
186	        // Validate address ownership if shipping
187	        if (addressId != null) {
188	            ShippingAddress addr = addressRepository.findById(addressId)
189	                    .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
190	            if (!addr.getAccountId().equals(accountId)) {
191	                throw new SecurityException("Cannot use another user's shipping address");
192	            }
193	        }
194	
195	        RewardItem reward = rewardRepository.findById(rewardId)
196	                .orElseThrow(() -> new IllegalArgumentException("Reward not found: " + rewardId));
197	
198	        int qty = quantity != null ? quantity : 1;
199	
200	        // Check per-user limit
201	        long existingOrders = orderRepository.countByRewardIdAndAccountId(rewardId, accountId);
202	        if (existingOrders + qty > reward.getPerUserLimit()) {
203	            throw new IllegalStateException("Per-user limit exceeded for this reward");
204	        }
205	
206	        // Check inventory
207	        if (reward.getInventoryCount() < qty) {
208	            throw new IllegalStateException("Insufficient inventory for this reward");
209	        }
210	
211	        // Decrement inventory
212	        reward.setInventoryCount(reward.getInventoryCount() - qty);
213	        reward.setUpdatedAt(LocalDateTime.now());
214	        rewardRepository.save(reward);
215	
216	        RewardOrder order = new RewardOrder();
217	        order.setRewardId(rewardId);
218	        order.setAccountId(accountId);
219	        order.setQuantity(qty);
220	        order.setFulfillmentType(fulfillmentType != null ? fulfillmentType : reward.getFulfillmentType());
221	        order.setShippingAddressId(addressId);
222	        order.setStatus("ORDERED");
223	        order.setStatusChangedAt(LocalDateTime.now());
224	        order.setCreatedAt(LocalDateTime.now());
225	        order.setUpdatedAt(LocalDateTime.now());
226	
227	        RewardOrder saved = orderRepository.save(order);
228	
229	        auditService.log(accountId, null, "ORDER_PLACED",
230	                "RewardOrder", saved.getId().toString(),
231	                null, "ORDERED", null, null);
232	
233	        return saved;
234	    }
