236	    @Transactional
237	    public RewardOrder transitionOrder(Long orderId, String toState, String note,
238	                                        Long actorId, String actorRole) {
239	        RewardOrder order = orderRepository.findById(orderId)
240	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
241	        enforceOrderScope(order, actorId, actorRole);
242	
243	        String beforeState = order.getStatus();
244	        Map<String, Set<String>> transitions = "VOUCHER".equals(order.getFulfillmentType())
245	                ? VOUCHER_TRANSITIONS : PHYSICAL_TRANSITIONS;
246	
247	        Set<String> allowedNext = transitions.get(beforeState);
248	        if (allowedNext == null || !allowedNext.contains(toState)) {
249	            throw new IllegalStateException(
250	                    "Invalid transition from " + beforeState + " to " + toState);
251	        }
252	
253	        order.setStatus(toState);
254	        order.setStatusChangedAt(LocalDateTime.now());
255	        if (note != null) order.setNote(note);
256	        order.setUpdatedAt(LocalDateTime.now());
257	
258	        RewardOrder saved = orderRepository.save(order);
259	
260	        auditService.log(actorId, actorRole, "ORDER_TRANSITIONED",
261	                "RewardOrder", saved.getId().toString(),
262	                beforeState, toState, null, null);
263	
264	        return saved;
265	    }
