316	    @Transactional
317	    public FulfillmentException transitionException(Long exceptionId, String toState,
318	                                                     Long actorId, String actorRole) {
319	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
320	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
321	
322	        String beforeState = exc.getStatus();
323	        Set<String> allowedNext = EXCEPTION_TRANSITIONS.get(beforeState);
324	        if (allowedNext == null || !allowedNext.contains(toState)) {
325	            throw new IllegalStateException(
326	                    "Invalid transition from " + beforeState + " to " + toState);
327	        }
328	
329	        exc.setStatus(toState);
330	        if ("RESOLVED".equals(toState) || "REJECTED".equals(toState)) {
331	            exc.setResolvedBy(actorId);
332	        }
333	        exc.setUpdatedAt(LocalDateTime.now());
334	
335	        FulfillmentException saved = exceptionRepository.save(exc);
336	
337	        auditService.log(actorId, actorRole, "EXCEPTION_TRANSITIONED",
