17	
18	    private static final Map<String, Set<String>> WO_TRANSITIONS = Map.of(
19	            "NEW_ALERT", Set.of("ACKNOWLEDGED"),
20	            "ACKNOWLEDGED", Set.of("DISPATCHED"),
21	            "DISPATCHED", Set.of("IN_PROGRESS"),
22	            "IN_PROGRESS", Set.of("RESOLVED"),
