50	    /**
51	     * Enforces that the actor is authorized to access the given work order.
52	     * ADMINs bypass; ORG_OPERATORs must share an org scope with the work order's creator.
53	     */
54	    private void enforceWorkOrderScope(WorkOrder wo, Long actorId, String actorRole) {
55	        orgScopeService.enforceCreatorOrgScope(actorId, actorRole, wo.getCreatedBy());
56	    }
