80	    @Transactional
81	    public WorkOrder transitionWorkOrder(Long id, String toStatus, Long actorId, String actorRole) {
82	        WorkOrder wo = workOrderRepository.findById(id)
83	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + id));
84	        enforceWorkOrderScope(wo, actorId, actorRole);
85	
86	        String beforeStatus = wo.getStatus();
87	        Set<String> allowedNext = WO_TRANSITIONS.get(beforeStatus);
88	        if (allowedNext == null || !allowedNext.contains(toStatus)) {
89	            throw new IllegalStateException(
90	                    "Invalid transition from " + beforeStatus + " to " + toStatus);
91	        }
92	
93	        wo.setStatus(toStatus);
94	        wo.setUpdatedAt(LocalDateTime.now());
95	
96	        // Record first_response_at on first ACKNOWLEDGED
97	        if ("ACKNOWLEDGED".equals(toStatus) && wo.getFirstResponseAt() == null) {
98	            wo.setFirstResponseAt(LocalDateTime.now());
99	        }
100	
101	        // Record closed_at on CLOSED
102	        if ("CLOSED".equals(toStatus)) {
103	            wo.setClosedAt(LocalDateTime.now());
104	        }
105	
106	        WorkOrder saved = workOrderRepository.save(wo);
107	
108	        auditService.log(actorId, null, "WORK_ORDER_TRANSITIONED",
