208	    public Long computeFirstResponseSeconds(WorkOrder wo) {
209	        if (wo.getFirstResponseAt() == null || wo.getCreatedAt() == null) return null;
210	        return Duration.between(wo.getCreatedAt(), wo.getFirstResponseAt()).getSeconds();
211	    }
212	
213	    public Long computeTimeToCloseSeconds(WorkOrder wo) {
214	        if (wo.getClosedAt() == null || wo.getCreatedAt() == null) return null;
215	        return Duration.between(wo.getCreatedAt(), wo.getClosedAt()).getSeconds();
216	    }
217	
218	    public List<WorkOrder> listWorkOrders(String statusFilter, Long actorId, boolean isAdmin) {
219	        if (isAdmin) {
220	            if (statusFilter != null && !statusFilter.isBlank()) {
221	                return workOrderRepository.findByStatus(statusFilter);
222	            }
223	            return workOrderRepository.findAll();
224	        }
225	        // ORG_OPERATOR: scoped to work orders created by anyone in the same org scope
226	        List<String> orgIds = orgScopeService.getOrgScopes(actorId);
227	        List<Long> orgAccountIds = orgScopeService.getAccountIdsInOrgScopes(orgIds);
228	        if (orgAccountIds.isEmpty()) return List.of();
229	        if (statusFilter != null && !statusFilter.isBlank()) {
230	            return workOrderRepository.findByCreatedByInAndStatus(orgAccountIds, statusFilter);
231	        }
232	        return workOrderRepository.findByCreatedByIn(orgAccountIds);
233	    }
234	}
