1	package com.croh.security;
2	
3	import com.croh.account.RoleMembership;
4	import com.croh.account.RoleMembershipRepository;
5	import org.springframework.stereotype.Service;
6	
7	import java.util.List;
8	
9	/**
10	 * Reusable helper for organization-scope authorization checks.
11	 *
12	 * All enforcement is object-centric: privileged objects carry an explicit
13	 * {@code organizationId} and authorization is checked against that value,
14	 * never inferred from the object creator's current role memberships.
15	 */
16	@Service
17	public class OrgScopeService {
18	
19	    private final RoleMembershipRepository roleMembershipRepository;
20	
21	    public OrgScopeService(RoleMembershipRepository roleMembershipRepository) {
22	        this.roleMembershipRepository = roleMembershipRepository;
23	    }
24	
25	    /**
26	     * Returns the list of organization scope IDs the actor has approved
27	     * ORG_OPERATOR memberships for.
28	     */
29	    public List<String> getOrgScopes(Long actorId) {
30	        return roleMembershipRepository.findByAccountIdAndStatus(
31	                        actorId, RoleMembership.RoleMembershipStatus.APPROVED).stream()
32	                .filter(m -> "ORG_OPERATOR".equals(m.getRoleType()))
33	                .map(RoleMembership::getScopeId)
34	                .filter(s -> s != null)
35	                .toList();
36	    }
37	
38	    /**
39	     * Enforces that the actor is authorized for the given object-bound
40	     * organization ID.  ADMINs always pass.  For any other role, the actor
41	     * must hold an approved ORG_OPERATOR membership whose scope_id matches
42	     * {@code objectOrgId}.
43	     *
44	     * <p>Fail-safe: if {@code objectOrgId} is null (legacy data without org
45	     * binding), non-admin access is rejected.
46	     *
47	     * @throws SecurityException if the actor is not authorized
48	     */
49	    public void enforceOrgScope(Long actorId, String actorRole, String objectOrgId) {
50	        if ("ADMIN".equals(actorRole)) {
51	            return;
52	        }
53	        if (objectOrgId == null) {
54	            throw new SecurityException(
55	                    "Object has no organization binding; non-admin access denied");
56	        }
57	        List<String> actorScopes = getOrgScopes(actorId);
58	        if (!actorScopes.contains(objectOrgId)) {
59	            throw new SecurityException(
60	                    "Not authorized for organization: " + objectOrgId);
61	        }
62	    }
63	}
