119	    @Transactional
120	    public ShippingAddress createAddress(Long accountId, String line1, String line2,
121	                                          String city, String state, String zip) {
122	        if (!STATE_PATTERN.matcher(state).matches()) {
123	            throw new IllegalArgumentException("State must be a 2-character uppercase code");
124	        }
125	        if (!ZIP_PATTERN.matcher(zip).matches()) {
126	            throw new IllegalArgumentException("Zip code must be in 5-digit or 5+4 format");
127	        }
128	
129	        // Auto-primary: first address for an account becomes primary
130	        List<ShippingAddress> existing = addressRepository.findByAccountId(accountId);
131	        boolean shouldBePrimary = existing.isEmpty();
132	
133	        ShippingAddress addr = new ShippingAddress();
134	        addr.setAccountId(accountId);
135	        addr.setAddressLine1Encrypted(encryptionService.encrypt(line1));
136	        addr.setAddressLine2Encrypted(line2 != null ? encryptionService.encrypt(line2) : null);
137	        addr.setCity(city);
138	        addr.setStateCode(state);
139	        addr.setZipCode(zip);
140	        addr.setPrimary(shouldBePrimary);
141	        addr.setCreatedAt(LocalDateTime.now());
142	
143	        ShippingAddress saved = addressRepository.save(addr);
144	
145	        auditService.log(accountId, null, "ADDRESS_CREATED",
146	                "ShippingAddress", saved.getId().toString(),
147	                null, shouldBePrimary ? "PRIMARY" : null, null, null);
148	
149	        return saved;
150	    }
