299	        exception.setOrderId(orderId);
300	        exception.setReasonCode(reasonCode);
301	        exception.setDescription(description);
302	        exception.setStatus("OPEN");
303	        exception.setCreatedBy(actorId);
304	        exception.setCreatedAt(LocalDateTime.now());
305	        exception.setUpdatedAt(LocalDateTime.now());
306	
307	        FulfillmentException saved = exceptionRepository.save(exception);
308	
309	        auditService.log(actorId, null, "EXCEPTION_CREATED",
310	                "FulfillmentException", saved.getId().toString(),
311	                null, "OPEN", reasonCode, null);
