315	
316	    @Transactional
317	    public FulfillmentException transitionException(Long exceptionId, String toState,
318	                                                     Long actorId, String actorRole) {
319	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
320	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
321	
322	        String beforeState = exc.getStatus();
323	        Set<String> allowedNext = EXCEPTION_TRANSITIONS.get(beforeState);
324	        if (allowedNext == null || !allowedNext.contains(toState)) {
325	            throw new IllegalStateException(
326	                    "Invalid transition from " + beforeState + " to " + toState);
327	        }
328	
329	        exc.setStatus(toState);
330	        if ("RESOLVED".equals(toState) || "REJECTED".equals(toState)) {
331	            exc.setResolvedBy(actorId);
332	        }
333	        exc.setUpdatedAt(LocalDateTime.now());
334	
335	        FulfillmentException saved = exceptionRepository.save(exc);
336	
337	        auditService.log(actorId, actorRole, "EXCEPTION_TRANSITIONED",
338	                "FulfillmentException", saved.getId().toString(),
339	                beforeState, toState, null, null);
340	
341	        return saved;
342	    }
343	
344	    @Transactional
345	    public FulfillmentException reopenException(Long exceptionId, String reasonCode, String note,
346	                                                 Long actorId, String actorRole) {
347	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
348	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
349	
350	        if (!"RESOLVED".equals(exc.getStatus()) && !"REJECTED".equals(exc.getStatus())) {
351	            throw new IllegalStateException("Can only reopen from RESOLVED or REJECTED state");
352	        }
353	
354	        String beforeState = exc.getStatus();
355	        exc.setStatus("OPEN");
356	        exc.setReopenReason(note);
357	        exc.setSupervisorApproval(true);
358	        exc.setResolvedBy(null);
359	        exc.setUpdatedAt(LocalDateTime.now());
360	
361	        FulfillmentException saved = exceptionRepository.save(exc);
362	
363	        auditService.log(actorId, actorRole, "EXCEPTION_REOPENED",
364	                "FulfillmentException", saved.getId().toString(),
365	                beforeState, "OPEN", reasonCode, null);
366	
367	        return saved;
368	    }
