81	    @Transactional
82	    public WorkOrder transitionWorkOrder(Long id, String toStatus, Long actorId, String actorRole) {
83	        WorkOrder wo = workOrderRepository.findById(id)
84	                .orElseThrow(() -> new IllegalArgumentException("Work order not found: " + id));
85	        enforceWorkOrderScope(wo, actorId, actorRole);
86	
87	        String beforeStatus = wo.getStatus();
88	        Set<String> allowedNext = WO_TRANSITIONS.get(beforeStatus);
89	        if (allowedNext == null || !allowedNext.contains(toStatus)) {
90	            throw new IllegalStateException(
91	                    "Invalid transition from " + beforeStatus + " to " + toStatus);
92	        }
93	
94	        wo.setStatus(toStatus);
95	        wo.setUpdatedAt(LocalDateTime.now());
96	
97	        // Record first_response_at on first ACKNOWLEDGED
98	        if ("ACKNOWLEDGED".equals(toStatus) && wo.getFirstResponseAt() == null) {
99	            wo.setFirstResponseAt(LocalDateTime.now());
100	        }
101	
102	        // Record closed_at on CLOSED
103	        if ("CLOSED".equals(toStatus)) {
104	            wo.setClosedAt(LocalDateTime.now());
105	        }
106	
107	        WorkOrder saved = workOrderRepository.save(wo);
