209	    public Long computeFirstResponseSeconds(WorkOrder wo) {
210	        if (wo.getFirstResponseAt() == null || wo.getCreatedAt() == null) return null;
211	        return Duration.between(wo.getCreatedAt(), wo.getFirstResponseAt()).getSeconds();
212	    }
213	
214	    public Long computeTimeToCloseSeconds(WorkOrder wo) {
215	        if (wo.getClosedAt() == null || wo.getCreatedAt() == null) return null;
216	        return Duration.between(wo.getCreatedAt(), wo.getClosedAt()).getSeconds();
217	    }
