219	    public List<WorkOrder> listWorkOrders(String statusFilter, Long actorId, boolean isAdmin) {
220	        if (isAdmin) {
221	            if (statusFilter != null && !statusFilter.isBlank()) {
222	                return workOrderRepository.findByStatus(statusFilter);
223	            }
224	            return workOrderRepository.findAll();
225	        }
226	        // ORG_OPERATOR: scoped to work orders bound to actor's org scopes
227	        List<String> orgIds = orgScopeService.getOrgScopes(actorId);
228	        if (orgIds.isEmpty()) return List.of();
229	        if (statusFilter != null && !statusFilter.isBlank()) {
230	            return workOrderRepository.findByOrganizationIdInAndStatus(orgIds, statusFilter);
231	        }
232	        return workOrderRepository.findByOrganizationIdIn(orgIds);
233	    }
